/**
 * Formulário de Nova Senha
 * Fluxo:
 * 1. Usuário acessa via link com token: /new-password?token=xyz
 * 2. Preenche a nova senha (2 campos iguais)
 * 3. Envia para o backend e vê o resultado na mesma página
 */

import { useEffect, useState } from "react";
import { useForm, Controller } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { useRouter, useSearchParams } from "next/navigation";
import Image from "next/image";
import { useTheme } from "@/context/ThemeContext";
import Input from "@/components/form/input/InputField";
import Label from "@/components/form/Label";
import { Button } from "@/components/ui/Button";
import { CheckCircleIcon, EyeCloseIcon, EyeIcon } from "@/icons";

// API URL do backend
const API_URL = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000/api/v1";

// Validação com Zod
const newPasswordSchema = z
  .object({
    password: z.string().min(8, "Senha deve ter no mínimo 8 caracteres"),
    confirmPassword: z.string().min(8, "Confirmação de senha é obrigatória"),
  })
  .refine((data) => data.password === data.confirmPassword, {
    message: "As senhas não coincidem",
    path: ["confirmPassword"],
  });

type NewPasswordFormData = z.infer<typeof newPasswordSchema>;

function Header() {
  const { theme } = useTheme();
  const [mounted, setMounted] = useState(false);
  useEffect(() => setMounted(true), []);

  return (
    <div className="text-center mb-6">
      {mounted ? (
        <div className="flex justify-center mb-2">
          <Image
            src={theme === "dark" ? "/images/logo/auth-logo-dark.svg" : "/images/logo/auth-logo.svg"}
            alt="HB Track"
            width={180}
            height={60}
            priority
          />
        </div>
      ) : (
        <div style={{ width: 180, height: 60 }} className="mx-auto mb-2" />
      )}
      <p
        className="text-sm text-gray-600 dark:text-gray-400"
        style={{ fontFamily: '"Inter", sans-serif', fontWeight: 300 }}
      >
        Dados que decidem jogos
      </p>
    </div>
  );
}

export default function NewPasswordForm() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const token = searchParams.get("token");

  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(
    token ? null : "Token inválido. Por favor, solicite um novo link de recuperação."
  );

  const {
    control,
    handleSubmit,
    formState: { errors },
  } = useForm<NewPasswordFormData>({
    resolver: zodResolver(newPasswordSchema),
    defaultValues: {
      password: "",
      confirmPassword: "",
    },
  });

  const onSubmit = async (data: NewPasswordFormData) => {
    if (!token) {
      setError("Token inválido");
      return;
    }

    setError(null);
    setIsLoading(true);

    try {
      const response = await fetch(`${API_URL}/auth/reset-password`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        credentials: "include", // Permite que o backend sete cookies HttpOnly
        body: JSON.stringify({
          token,
          new_password: data.password,
          confirm_password: data.confirmPassword,
        }),
      });

      const responseData = await response.json();

      if (!response.ok) {
        setError(responseData.detail?.message || responseData.message || "Erro ao redefinir senha");
        setIsLoading(false);
        return;
      }

      // Backend já setou os cookies HttpOnly - redirecionar direto para /inicio
      // Não precisa de login manual!
      router.replace(responseData.redirect_to || "/inicio");
      router.refresh(); // Força AuthContext a reconhecer a sessão
    } catch (err) {
      setError("Erro ao conectar com o servidor");
      setIsLoading(false);
    }
  };

  // Sucesso
  if (isSubmitted) {
    return (
      <div className="flex min-h-screen items-center justify-center bg-gray-50 dark:bg-gray-900 px-4">
        <div className="w-full max-w-xs text-center">
          <Header />
          <div className="mb-8">
            <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-green-100 dark:bg-green-900/20 border border-green-300 dark:border-green-800 mb-4">
              <CheckCircleIcon className="w-8 h-8 text-green-600 dark:text-green-400" />
            </div>
            <h2 className="text-xl font-semibold text-green-600 dark:text-green-400 mb-4">
              Senha Alterada com Sucesso!
            </h2>
            <p className="text-gray-600 dark:text-gray-400">
              Sua senha foi alterada com sucesso. Agora você pode fazer login usando seu email e a nova senha.
            </p>
          </div>

          <Button className="w-full" size="sm" onClick={() => router.push("/signin")}>
            Ir para o Login
          </Button>
        </div>
      </div>
    );
  }

  // Token ausente
  if (!token) {
    return (
      <div className="flex min-h-screen items-center justify-center bg-gray-50 dark:bg-gray-900 px-4">
        <div className="w-full max-w-xs text-center">
          <Header />
          <div className="mb-8">
            <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-red-100 dark:bg-red-900/20 border border-red-300 dark:border-red-800 mb-4">
              <span className="text-2xl">!</span>
            </div>
            <h2 className="text-xl font-semibold text-gray-800 dark:text-white mb-2">Link inválido</h2>
            <p className="text-gray-600 dark:text-gray-400 mb-6">
              Token inválido. Solicite um novo link de recuperação.
            </p>
          </div>

          <Button className="w-full" size="sm" onClick={() => router.push("/reset-password")}>
            Solicitar Novo Link
          </Button>
        </div>
      </div>
    );
  }

  // Formulário principal
  return (
    <div className="flex min-h-screen items-center justify-center bg-gray-50 dark:bg-gray-900 px-4">
      <div className="w-full max-w-xs">
        <Header />
        <div className="text-center mb-4">
          <h2 className="text-xl font-semibold text-gray-700 dark:text-gray-300 mb-2">Definir Nova Senha</h2>
          <p className="text-gray-600 dark:text-gray-400 text-sm">
            Digite sua nova senha nos campos abaixo. As senhas devem ser idênticas.
          </p>
        </div>

        <form onSubmit={handleSubmit(onSubmit)}>
          <div className="space-y-4">
            {error && (
              <div className="p-3 text-sm text-error-700 dark:text-error-400 bg-error-100 dark:bg-error-950/30 rounded-lg border border-error-300 dark:border-error-800">
                {error}
              </div>
            )}

            {/* Nova Senha */}
            <div>
              <Label className="text-gray-700 dark:text-gray-300 mb-2 block">
                Nova Senha <span className="text-error-500">*</span>
              </Label>
              <div className="relative">
                <Controller
                  name="password"
                  control={control}
                  render={({ field }) => (
                    <Input
                      type={showPassword ? "text" : "password"}
                      placeholder="Digite sua nova senha"
                      disabled={isLoading}
                      onChange={field.onChange}
                      defaultValue={field.value}
                      error={!!errors.password}
                    />
                  )}
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-200"
                >
                  {showPassword ? <EyeIcon className="w-5 h-5" /> : <EyeCloseIcon className="w-5 h-5" />}
                </button>
              </div>
              {errors.password && (
                <p className="mt-1 text-xs text-red-600 dark:text-red-400">{errors.password.message}</p>
              )}
            </div>

            {/* Confirmar Senha */}
            <div>
              <Label className="text-gray-700 dark:text-gray-300 mb-2 block">
                Confirmar Senha <span className="text-error-500">*</span>
              </Label>
              <div className="relative">
                <Controller
                  name="confirmPassword"
                  control={control}
                  render={({ field }) => (
                    <Input
                      type={showConfirmPassword ? "text" : "password"}
                      placeholder="Repita sua nova senha"
                      disabled={isLoading}
                      onChange={field.onChange}
                      defaultValue={field.value}
                      error={!!errors.confirmPassword}
                    />
                  )}
                />
                <button
                  type="button"
                  onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-200"
                >
                  {showConfirmPassword ? <EyeIcon className="w-5 h-5" /> : <EyeCloseIcon className="w-5 h-5" />}
                </button>
              </div>
              {errors.confirmPassword && (
                <p className="mt-1 text-xs text-red-600 dark:text-red-400">{errors.confirmPassword.message}</p>
              )}
            </div>

            <Button className="w-full" size="sm" disabled={isLoading} onClick={handleSubmit(onSubmit)}>
              {isLoading ? "Processando..." : "Definir Nova Senha"}
            </Button>
          </div>
        </form>
      </div>
    </div>
  );
}

'use client'

import { useState, useEffect } from 'react'
import { useRouter } from 'next/navigation'
import { CheckCircle, AlertCircle, Lock, User, Loader2 } from 'lucide-react'
import AthleteProfileForm, { type AthleteFormData } from './forms/AthleteProfileForm'
import CoachProfileForm, { type CoachFormData } from './forms/CoachProfileForm'
import CoordinatorProfileForm, { type CoordinatorFormData } from './forms/CoordinatorProfileForm'
import GenericProfileForm, { type GenericFormData } from './forms/GenericProfileForm'

// API URL para chamadas ao backend
const API_URL = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:8000/api/v1'

interface WelcomeFlowProps {
  token: string
}

interface WelcomeInfo {
  valid: boolean
  email: string
  full_name?: string
  role: string
  invitee_kind: string
  team_name?: string
  organization_name?: string
  expires_at: string
}

type Step = 'loading' | 'error' | 'password' | 'profile' | 'success'

export default function WelcomeFlow({ token }: WelcomeFlowProps) {
  const router = useRouter()
  
  // Estados
  const [step, setStep] = useState<Step>('loading')
  const [welcomeInfo, setWelcomeInfo] = useState<WelcomeInfo | null>(null)
  const [error, setError] = useState<string | null>(null)
  const [errorCode, setErrorCode] = useState<string | null>(null)
  
  // Form fields - Step 1 (Senha)
  const [password, setPassword] = useState('')
  const [confirmPassword, setConfirmPassword] = useState('')
  
  const [isSubmitting, setIsSubmitting] = useState(false)

  // Verificar token ao carregar
  useEffect(() => {
    verifyToken()
  }, [token])

  const verifyToken = async () => {
    try {
      const response = await fetch(`${API_URL}/auth/welcome/verify?token=${token}`, {
        credentials: 'include',
      })
      
      const data = await response.json()
      
      if (!response.ok) {
        setError(data.detail?.message || 'Token inválido')
        setErrorCode(data.detail?.code || 'UNKNOWN')
        setStep('error')
        return
      }
      
      setWelcomeInfo(data)
      setStep('password')
    } catch (err) {
      setError('Erro ao verificar convite. Tente novamente.')
      setStep('error')
    }
  }

  const handlePasswordSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    setError(null)
    
    // Validações
    if (password.length < 8) {
      setError('Senha deve ter no mínimo 8 caracteres')
      return
    }
    
    if (password !== confirmPassword) {
      setError('As senhas não conferem')
      return
    }
    
    // Avançar para step 2
    setStep('profile')
  }

  const handleProfileSubmit = async (data: AthleteFormData | CoachFormData | CoordinatorFormData | GenericFormData) => {
    setError(null)
    setIsSubmitting(true)
    
    // Validação
    if (!data.full_name.trim() || data.full_name.trim().length < 2) {
      setError('Nome completo é obrigatório')
      setIsSubmitting(false)
      return
    }
    
    try {
      const response = await fetch(`${API_URL}/auth/welcome/complete`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({
          token,
          password,
          confirm_password: confirmPassword,
          ...data,
        }),
      })
      
      const responseData = await response.json()
      
      if (!response.ok) {
        setError(responseData.detail?.message || 'Erro ao completar cadastro')
        setIsSubmitting(false)
        return
      }
      
      // Sucesso!
      setStep('success')
      
      // Redirecionar após 2 segundos
      // Todos redirecionam para /inicio
      setTimeout(() => {
        router.replace('/inicio')
        router.refresh()
      }, 2000)
      
    } catch (err) {
      setError('Erro de conexão. Tente novamente.')
      setIsSubmitting(false)
    }
  }

  // ============================================================================
  // Render: Loading
  // ============================================================================
  if (step === 'loading') {
    return (
      <div data-testid="welcome-loading" className="min-h-screen flex items-center justify-center bg-slate-50 dark:bg-slate-950">
        <div className="text-center">
          <Loader2 className="w-12 h-12 animate-spin text-slate-400 mx-auto mb-4" />
          <p className="text-slate-600 dark:text-slate-400">Verificando convite...</p>
        </div>
      </div>
    )
  }

  // ============================================================================
  // Render: Error
  // ============================================================================
  if (step === 'error') {
    return (
      <div data-testid="welcome-error" className="min-h-screen flex items-center justify-center bg-slate-50 dark:bg-slate-950 px-4">
        <div className="max-w-md w-full bg-white dark:bg-slate-900 rounded-2xl shadow-xl p-8 text-center">
          <div className="w-16 h-16 bg-red-100 dark:bg-red-900/30 rounded-full flex items-center justify-center mx-auto mb-6">
            <AlertCircle className="w-8 h-8 text-red-600 dark:text-red-400" />
          </div>
          
          <h1 data-testid="welcome-error-title" className="text-2xl font-bold text-slate-900 dark:text-white mb-2">
            {errorCode === 'TOKEN_EXPIRED' ? 'Convite Expirado' : 
             errorCode === 'TOKEN_USED' ? 'Convite Já Utilizado' : 
             'Convite Inválido'}
          </h1>
          
          <p className="text-slate-600 dark:text-slate-400 mb-8">
            {error || 'Este link de convite não é válido.'}
          </p>
          
          <div className="space-y-3">
            <button
              onClick={() => router.push('/signin')}
              className="w-full px-4 py-3 bg-slate-900 dark:bg-slate-100 text-white dark:text-black font-semibold rounded-lg hover:opacity-90 transition-all"
            >
              Ir para Login
            </button>
            
            {errorCode === 'TOKEN_EXPIRED' && (
              <p className="text-sm text-slate-500">
                Entre em contato com quem enviou o convite para solicitar um novo.
              </p>
            )}
          </div>
        </div>
      </div>
    )
  }

  // ============================================================================
  // Render: Success
  // ============================================================================
  if (step === 'success') {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50 dark:bg-slate-950 px-4">
        <div className="max-w-md w-full bg-white dark:bg-slate-900 rounded-2xl shadow-xl p-8 text-center">
          <div className="w-16 h-16 bg-emerald-100 dark:bg-emerald-900/30 rounded-full flex items-center justify-center mx-auto mb-6">
            <CheckCircle className="w-8 h-8 text-emerald-600 dark:text-emerald-400" />
          </div>
          
          <h1 className="text-2xl font-bold text-slate-900 dark:text-white mb-2">
            Bem-vindo(a)! 🎉
          </h1>
          
          <p className="text-slate-600 dark:text-slate-400 mb-4">
            Seu cadastro foi completado com sucesso.
          </p>
          
          <p className="text-sm text-slate-500">
            Redirecionando...
          </p>
          
          <Loader2 className="w-6 h-6 animate-spin text-slate-400 mx-auto mt-4" />
        </div>
      </div>
    )
  }

  // ============================================================================
  // Render: Steps (Password & Profile)
  // ============================================================================
  const currentStep = step === 'password' ? 1 : 2

  return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50 dark:bg-slate-950 px-4 py-8">
      <div className="max-w-md w-full">
        {/* Header */}
        <div className="text-center mb-8">
          <h1 className="text-3xl font-bold text-slate-900 dark:text-white mb-2">
            Complete seu cadastro
          </h1>
          {welcomeInfo && (
            <p className="text-slate-600 dark:text-slate-400">
              {welcomeInfo.organization_name && (
                <span className="font-medium">{welcomeInfo.organization_name}</span>
              )}
              {welcomeInfo.team_name && (
                <span> • Equipe {welcomeInfo.team_name}</span>
              )}
            </p>
          )}
        </div>

        {/* Stepper */}
        <div className="flex items-center justify-center gap-2 mb-8">
          <div className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-sm font-medium transition-all ${
            currentStep >= 1 
              ? 'bg-slate-900 dark:bg-slate-100 text-white dark:text-black' 
              : 'bg-slate-200 dark:bg-slate-800 text-slate-500'
          }`}>
            <Lock className="w-4 h-4" />
            Senha
          </div>
          
          <div className="w-8 h-0.5 bg-slate-300 dark:bg-slate-700" />
          
          <div className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-sm font-medium transition-all ${
            currentStep >= 2 
              ? 'bg-slate-900 dark:bg-slate-100 text-white dark:text-black' 
              : 'bg-slate-200 dark:bg-slate-800 text-slate-500'
          }`}>
            <User className="w-4 h-4" />
            Perfil
          </div>
        </div>

        {/* Card */}
        <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-xl p-8">
          {/* Error Message */}
          {error && (
            <div className="mb-6 p-4 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-900/50 rounded-lg">
              <p className="text-sm text-red-700 dark:text-red-400">{error}</p>
            </div>
          )}

          {/* Step 1: Password */}
          {step === 'password' && (
            <form data-testid="welcome-password-form" onSubmit={handlePasswordSubmit} className="space-y-6">
              <div>
                <p className="text-slate-600 dark:text-slate-400 text-sm mb-6">
                  Olá, <span className="font-semibold">{welcomeInfo?.email}</span>!
                  <br />
                  Crie uma senha segura para acessar sua conta.
                </p>
              </div>
              
              <div>
                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">
                  Nova Senha *
                </label>
                <input
                  type="password"
                  data-testid="welcome-password-input"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg text-slate-900 dark:text-white placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-slate-900 dark:focus:ring-slate-100"
                  placeholder="Mínimo 8 caracteres"
                  minLength={8}
                  required
                />
              </div>
              
              <div>
                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">
                  Confirmar Senha *
                </label>
                <input
                  type="password"
                  value={confirmPassword}
                  onChange={(e) => setConfirmPassword(e.target.value)}
                  className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg text-slate-900 dark:text-white placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-slate-900 dark:focus:ring-slate-100"
                  placeholder="Repita a senha"
                  minLength={8}
                  required
                />
              </div>

              {/* Password Requirements */}
              <div className="p-3 bg-slate-50 dark:bg-slate-800 rounded-lg">
                <p className="text-xs font-medium text-slate-600 dark:text-slate-400 mb-2">
                  Requisitos da senha:
                </p>
                <ul className="text-xs text-slate-500 space-y-1">
                  <li className={password.length >= 8 ? 'text-emerald-600' : ''}>
                    • Mínimo 8 caracteres {password.length >= 8 && '✓'}
                  </li>
                  <li className={password === confirmPassword && password.length > 0 ? 'text-emerald-600' : ''}>
                    • Senhas devem coincidir {password === confirmPassword && password.length > 0 && '✓'}
                  </li>
                </ul>
              </div>
              
              <button
                type="submit"
                className="w-full px-4 py-3 bg-slate-900 dark:bg-slate-100 text-white dark:text-black font-semibold rounded-lg hover:opacity-90 transition-all"
              >
                Continuar
              </button>
            </form>
          )}

          {/* Step 2: Profile - Formulário dinâmico baseado em invitee_kind */}
          {step === 'profile' && welcomeInfo && (
            <>
              {welcomeInfo.invitee_kind === 'athlete' && (
                <AthleteProfileForm
                  initialData={{
                    fullName: welcomeInfo.full_name || '',
                    email: welcomeInfo.email
                  }}
                  onBack={() => setStep('password')}
                  onSubmit={handleProfileSubmit}
                  isSubmitting={isSubmitting}
                  error={error}
                />
              )}
              
              {welcomeInfo.invitee_kind === 'coach' && (
                <CoachProfileForm
                  initialData={{
                    fullName: welcomeInfo.full_name || '',
                    email: welcomeInfo.email
                  }}
                  onBack={() => setStep('password')}
                  onSubmit={handleProfileSubmit}
                  isSubmitting={isSubmitting}
                  error={error}
                />
              )}
              
              {welcomeInfo.invitee_kind === 'coordinator' && (
                <CoordinatorProfileForm
                  initialData={{
                    fullName: welcomeInfo.full_name || '',
                    email: welcomeInfo.email
                  }}
                  onBack={() => setStep('password')}
                  onSubmit={handleProfileSubmit}
                  isSubmitting={isSubmitting}
                  error={error}
                />
              )}
              
              {(!welcomeInfo.invitee_kind || 
                !['athlete', 'coach', 'coordinator'].includes(welcomeInfo.invitee_kind)) && (
                <GenericProfileForm
                  initialData={{
                    fullName: welcomeInfo.full_name || '',
                    email: welcomeInfo.email
                  }}
                  role={welcomeInfo.role}
                  onBack={() => setStep('password')}
                  onSubmit={handleProfileSubmit}
                  isSubmitting={isSubmitting}
                  error={error}
                />
              )}
            </>
          )}
        </div>

        {/* Footer */}
        <p className="text-center text-xs text-slate-500 mt-6">
          Ao continuar, você concorda com nossos termos de uso.
        </p>
      </div>
    </div>
  )
}

/**
 * ConfirmStep - Etapa final de confirmação e salvamento
 * 
 * Features:
 * - Opções do que importar (equipes, jogos, fases)
 * - Resumo final
 * - Feedback de salvamento
 */

'use client';

import { useState, useCallback } from 'react';
import { 
  CheckCircle, 
  Loader2, 
  Users, 
  Calendar, 
  Layers,
  AlertCircle,
  Trophy,
} from 'lucide-react';
import { cn } from '@/lib/utils';
import { useCompetitionV2Context } from '@/context/CompetitionV2Context';
import { useCompetitionV2 } from '@/lib/hooks/useCompetitionsV2';
import { competitionsV2Service } from '@/lib/api/competitions-v2';
import type { CompetitionV2Create } from '@/lib/api/competitions-v2';

interface ConfirmStepProps {
  teamId: string;
  onSuccess: (competitionId: string) => void;
  onBack: () => void;
}

export default function ConfirmStep({ teamId, onSuccess, onBack }: ConfirmStepProps) {
  const { extractedData, setCompetition, setCompetitionId } = useCompetitionV2Context();
  
  const [importOptions, setImportOptions] = useState({
    createPhases: true,
    createTeams: true,
    createMatches: true,
  });
  
  const [isSaving, setIsSaving] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [savedCompetitionId, setSavedCompetitionId] = useState<string | null>(null);

  if (!extractedData) {
    return (
      <div className="text-center py-12">
        <p className="text-gray-500">Nenhum dado para salvar</p>
        <button
          onClick={onBack}
          className="mt-4 text-amber-600 hover:text-amber-700 font-medium"
        >
          Voltar
        </button>
      </div>
    );
  }

  const totalTeams = extractedData.teams.length;
  const totalMatches = extractedData.phases.reduce((acc, p) => acc + p.matches.length, 0);
  const totalPhases = extractedData.phases.length;

  const handleSave = async () => {
    setIsSaving(true);
    setError(null);
    
    try {
      // 1. Criar competição
      const competitionData: CompetitionV2Create = {
        team_id: teamId,
        name: extractedData.name,
        season: extractedData.season,
        organization: extractedData.organization,
        modality: extractedData.modality,
        competition_type: extractedData.competition_type,
        format_details: extractedData.format_details,
        tiebreaker_criteria: extractedData.tiebreaker_criteria,
        status: 'draft',
      };
      
      const created = await competitionsV2Service.create(competitionData);
      setSavedCompetitionId(created.id);
      
      // 2. Importar dados da IA (equipes, fases, jogos)
      const fullCompetition = await competitionsV2Service.importFromAI(
        created.id,
        extractedData,
        importOptions
      );
      
      setCompetition(fullCompetition);
      setCompetitionId(created.id);
      
      // 3. Aguardar um pouco para mostrar sucesso
      await new Promise(resolve => setTimeout(resolve, 1000));
      
      onSuccess(created.id);
    } catch (err) {
      console.error('Error saving competition:', err);
      setError(err instanceof Error ? err.message : 'Erro ao salvar competição');
    } finally {
      setIsSaving(false);
    }
  };

  const toggleOption = (option: keyof typeof importOptions) => {
    setImportOptions(prev => ({
      ...prev,
      [option]: !prev[option],
    }));
  };

  if (isSaving) {
    return (
      <div className="flex flex-col items-center justify-center py-16">
        <div className="w-16 h-16 rounded-full bg-amber-100 dark:bg-amber-900/30 flex items-center justify-center mb-6">
          <Loader2 className="w-8 h-8 text-amber-600 dark:text-amber-400 animate-spin" />
        </div>
        <h2 className="text-xl font-semibold text-gray-900 dark:text-white mb-2">
          Salvando competição...
        </h2>
        <p className="text-gray-600 dark:text-gray-400">
          Aguarde enquanto criamos tudo para você
        </p>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="text-center mb-6">
        <div className="inline-flex items-center justify-center w-12 h-12 rounded-full bg-amber-100 dark:bg-amber-900/30 mb-3">
          <Trophy className="w-6 h-6 text-amber-600 dark:text-amber-400" />
        </div>
        <h2 className="text-xl font-bold text-gray-900 dark:text-white mb-1">
          Confirmar Importação
        </h2>
        <p className="text-sm text-gray-600 dark:text-gray-400">
          Escolha o que deseja importar e confirme
        </p>
      </div>

      {/* Error */}
      {error && (
        <div className="p-4 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-lg">
          <div className="flex items-start gap-3">
            <AlertCircle className="w-5 h-5 text-red-600 dark:text-red-400 flex-shrink-0" />
            <div>
              <p className="font-medium text-red-800 dark:text-red-300">Erro ao salvar</p>
              <p className="text-sm text-red-600 dark:text-red-400 mt-1">{error}</p>
            </div>
          </div>
        </div>
      )}

      {/* Summary Card */}
      <div className="p-5 bg-gradient-to-r from-amber-50 to-orange-50 dark:from-amber-900/20 dark:to-orange-900/20 border border-amber-200 dark:border-amber-800 rounded-xl">
        <h3 className="font-semibold text-gray-900 dark:text-white mb-4">
          {extractedData.name}
        </h3>
        <div className="grid grid-cols-3 gap-4 text-center">
          <div>
            <p className="text-2xl font-bold text-amber-600 dark:text-amber-400">{totalTeams}</p>
            <p className="text-xs text-gray-600 dark:text-gray-400">Equipes</p>
          </div>
          <div>
            <p className="text-2xl font-bold text-amber-600 dark:text-amber-400">{totalPhases}</p>
            <p className="text-xs text-gray-600 dark:text-gray-400">Fases</p>
          </div>
          <div>
            <p className="text-2xl font-bold text-amber-600 dark:text-amber-400">{totalMatches}</p>
            <p className="text-xs text-gray-600 dark:text-gray-400">Jogos</p>
          </div>
        </div>
      </div>

      {/* Import Options */}
      <div className="space-y-3">
        <h4 className="text-sm font-medium text-gray-700 dark:text-gray-300">
          O que importar?
        </h4>
        
        <ImportOption
          icon={Layers}
          label="Fases da competição"
          description={`${totalPhases} fase(s) encontrada(s)`}
          checked={importOptions.createPhases}
          onChange={() => toggleOption('createPhases')}
          disabled={totalPhases === 0}
        />
        
        <ImportOption
          icon={Users}
          label="Equipes adversárias"
          description={`${totalTeams} equipe(s) encontrada(s)`}
          checked={importOptions.createTeams}
          onChange={() => toggleOption('createTeams')}
          disabled={totalTeams === 0}
        />
        
        <ImportOption
          icon={Calendar}
          label="Jogos/Tabela"
          description={`${totalMatches} jogo(s) encontrado(s)`}
          checked={importOptions.createMatches}
          onChange={() => toggleOption('createMatches')}
          disabled={totalMatches === 0 || !importOptions.createTeams}
        />
        
        {!importOptions.createTeams && totalMatches > 0 && (
          <p className="text-xs text-yellow-600 dark:text-yellow-400 ml-9">
            ⚠️ Para importar jogos, é necessário importar as equipes
          </p>
        )}
      </div>

      {/* Info */}
      <div className="text-sm text-gray-500 dark:text-gray-400 bg-gray-50 dark:bg-gray-800/50 rounded-lg p-4">
        <p>
          💡 Você poderá editar todos os dados após a importação. 
          A competição será criada com status "Rascunho".
        </p>
      </div>

      {/* Actions */}
      <div className="flex justify-between pt-4 border-t border-gray-200 dark:border-gray-700">
        <button
          onClick={onBack}
          disabled={isSaving}
          className="px-4 py-2 text-gray-600 dark:text-gray-400 hover:text-gray-800 dark:hover:text-gray-200 font-medium disabled:opacity-50"
        >
          ← Voltar
        </button>
        <button
          onClick={handleSave}
          disabled={isSaving}
          className="inline-flex items-center gap-2 px-6 py-2.5 rounded-lg font-medium
                   bg-green-600 text-white hover:bg-green-700 shadow-md hover:shadow-lg 
                   transition-all disabled:opacity-50 disabled:cursor-not-allowed"
        >
          <CheckCircle className="w-4 h-4" />
          Criar Competição
        </button>
      </div>
    </div>
  );
}

// =============================================================================
// SUBCOMPONENTS
// =============================================================================

interface ImportOptionProps {
  icon: React.ElementType;
  label: string;
  description: string;
  checked: boolean;
  onChange: () => void;
  disabled?: boolean;
}

function ImportOption({ 
  icon: Icon, 
  label, 
  description, 
  checked, 
  onChange, 
  disabled 
}: ImportOptionProps) {
  return (
    <label className={cn(
      'flex items-center gap-3 p-3 rounded-lg border cursor-pointer transition-all',
      disabled 
        ? 'opacity-50 cursor-not-allowed bg-gray-50 dark:bg-gray-800/50 border-gray-200 dark:border-gray-700'
        : checked
        ? 'bg-amber-50 dark:bg-amber-900/20 border-amber-300 dark:border-amber-700'
        : 'bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700 hover:border-amber-300 dark:hover:border-amber-700'
    )}>
      <input
        type="checkbox"
        checked={checked}
        onChange={onChange}
        disabled={disabled}
        className="w-4 h-4 rounded border-gray-300 text-amber-600 
                 focus:ring-amber-500 disabled:opacity-50"
      />
      <Icon className={cn(
        'w-5 h-5',
        checked ? 'text-amber-600 dark:text-amber-400' : 'text-gray-400'
      )} />
      <div className="flex-1">
        <p className={cn(
          'font-medium text-sm',
          checked ? 'text-gray-900 dark:text-white' : 'text-gray-600 dark:text-gray-400'
        )}>
          {label}
        </p>
        <p className="text-xs text-gray-500 dark:text-gray-500">{description}</p>
      </div>
    </label>
  );
}

