/**
 * CreateCompetitionModal - Modal para criar/editar competição
 * 
 * Features:
 * - Formulário de criação/edição
 * - Validação de campos obrigatórios
 * - Feedback visual de loading/erro
 */

'use client';

import { useState, useEffect } from 'react';
import { X } from 'lucide-react';
import { useCompetitionsContext } from '@/context/CompetitionsContext';
import { useCreateCompetition, useUpdateCompetition, useCompetition } from '@/hooks/useCompetitions';
import { CompetitionCreate, CompetitionUpdate } from '@/lib/api/competitions';

const COMPETITION_KINDS = [
  { value: 'official', label: 'Oficial' },
  { value: 'friendly', label: 'Amistoso' },
  { value: 'training-game', label: 'Jogo-Treino' },
];

interface CreateCompetitionModalProps {
  editId?: string;
}

export default function CreateCompetitionModal({ editId }: CreateCompetitionModalProps) {
  const { 
    isCreateModalOpen, 
    closeCreateModal,
    isEditMode,
    editingCompetitionId 
  } = useCompetitionsContext();
  
  const competitionId = editId || editingCompetitionId;
  const isEditing = isEditMode || !!editId;
  
  const { data: competition } = useCompetition(isEditing ? competitionId : null);
  
  const createMutation = useCreateCompetition();
  const updateMutation = useUpdateCompetition();
  
  const [formData, setFormData] = useState<CompetitionCreate>({
    name: '',
    kind: 'official',
  });
  
  const [errors, setErrors] = useState<Record<string, string>>({});

  // Populate form when editing
  useEffect(() => {
    if (competition && isEditing) {
      setFormData({
        name: competition.name,
        kind: competition.kind || 'official',
      });
    }
  }, [competition, isEditing]);

  // Reset form when modal closes
  useEffect(() => {
    if (!isCreateModalOpen) {
      setFormData({
        name: '',
        kind: 'official',
      });
      setErrors({});
    }
  }, [isCreateModalOpen]);

  const validate = (): boolean => {
    const newErrors: Record<string, string> = {};
    
    if (!formData.name.trim()) {
      newErrors.name = 'Nome é obrigatório';
    } else if (formData.name.length < 3) {
      newErrors.name = 'Nome deve ter pelo menos 3 caracteres';
    }
    
    if (!formData.kind) {
      newErrors.kind = 'Tipo é obrigatório';
    }
    
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    
    if (!validate()) return;

    try {
      if (isEditing && competitionId) {
        const updateData: CompetitionUpdate = {
          name: formData.name,
          kind: formData.kind,
        };
        await updateMutation.mutateAsync({ 
          id: competitionId, 
          data: updateData 
        });
      } else {
        await createMutation.mutateAsync(formData);
      }
      closeCreateModal();
    } catch (error) {
      console.error('Erro ao salvar competição:', error);
    }
  };

  const handleChange = (
    e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>
  ) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    // Clear error when field is modified
    if (errors[name]) {
      setErrors(prev => ({ ...prev, [name]: '' }));
    }
  };

  const isLoading = createMutation.isPending || updateMutation.isPending;
  const error = createMutation.error || updateMutation.error;

  if (!isCreateModalOpen) return null;

  return (
    <div className="fixed inset-0 z-50">
      {/* Backdrop */}
      <div 
        className="fixed inset-0 bg-black/50 transition-opacity"
        onClick={closeCreateModal}
      />

      {/* Modal */}
      <div className="fixed inset-0 overflow-y-auto">
        <div className="flex min-h-full items-center justify-center p-4">
          <div className="w-full max-w-lg transform overflow-hidden rounded-2xl 
                        bg-white dark:bg-gray-800 p-6 shadow-xl transition-all relative">
            {/* Header */}
            <div className="flex items-center justify-between mb-6">
              <h2 className="text-xl font-semibold text-gray-900 dark:text-white">
                {isEditing ? 'Editar Competição' : 'Nova Competição'}
              </h2>
              <button
                onClick={closeCreateModal}
                className="p-2 rounded-lg text-gray-400 hover:text-gray-500 
                         hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors"
              >
                <X className="w-5 h-5" />
              </button>
            </div>

            {/* Error message */}
            {error && (
              <div className="mb-4 p-3 rounded-lg bg-red-50 dark:bg-red-900/20 
                            border border-red-200 dark:border-red-800">
                <p className="text-sm text-red-600 dark:text-red-400">
                  {error instanceof Error ? error.message : 'Erro ao salvar competição'}
                </p>
              </div>
            )}

            {/* Form */}
            <form onSubmit={handleSubmit} className="space-y-5">
                  {/* Name */}
                  <div>
                    <label 
                      htmlFor="name" 
                      className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1"
                    >
                      Nome *
                    </label>
                    <input
                      type="text"
                      id="name"
                      name="name"
                      value={formData.name}
                      onChange={handleChange}
                      placeholder="Ex: Campeonato Estadual 2025"
                      className={`w-full px-4 py-2 rounded-lg border 
                               ${errors.name 
                                 ? 'border-red-300 dark:border-red-600' 
                                 : 'border-gray-300 dark:border-gray-600'}
                               bg-white dark:bg-gray-700 text-gray-900 dark:text-white
                               placeholder-gray-400 focus:ring-2 focus:ring-amber-500 
                               focus:border-transparent transition-colors`}
                    />
                    {errors.name && (
                      <p className="mt-1 text-sm text-red-500">{errors.name}</p>
                    )}
                  </div>

                  {/* Kind */}
                  <div>
                    <label 
                      htmlFor="kind" 
                      className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1"
                    >
                      Tipo *
                    </label>
                    <select
                      id="kind"
                      name="kind"
                      value={formData.kind}
                      onChange={handleChange}
                      className={`w-full px-4 py-2 rounded-lg border 
                               ${errors.kind 
                                 ? 'border-red-300 dark:border-red-600' 
                                 : 'border-gray-300 dark:border-gray-600'}
                               bg-white dark:bg-gray-700 text-gray-900 dark:text-white
                               focus:ring-2 focus:ring-amber-500 focus:border-transparent 
                               transition-colors cursor-pointer`}
                    >
                      {COMPETITION_KINDS.map((kind) => (
                        <option key={kind.value} value={kind.value}>
                          {kind.label}
                        </option>
                      ))}
                    </select>
                    {errors.kind && (
                      <p className="mt-1 text-sm text-red-500">{errors.kind}</p>
                    )}
                  </div>

                  {/* Actions */}
                  <div className="flex items-center justify-end gap-3 pt-4">
                    <button
                      type="button"
                      onClick={closeCreateModal}
                      disabled={isLoading}
                      className="px-4 py-2 rounded-lg border border-gray-300 dark:border-gray-600
                               text-gray-700 dark:text-gray-300 hover:bg-gray-50 
                               dark:hover:bg-gray-700 transition-colors disabled:opacity-50"
                    >
                      Cancelar
                    </button>
                    <button
                      type="submit"
                      disabled={isLoading}
                      className="px-4 py-2 rounded-lg bg-amber-500 hover:bg-amber-600 
                               text-white font-medium transition-colors
                               disabled:opacity-50 disabled:cursor-not-allowed
                               flex items-center gap-2"
                    >
                      {isLoading && (
                        <svg 
                          className="animate-spin h-4 w-4" 
                          fill="none" 
                          viewBox="0 0 24 24"
                        >
                          <circle 
                            className="opacity-25" 
                            cx="12" 
                            cy="12" 
                            r="10" 
                            stroke="currentColor" 
                            strokeWidth="4"
                          />
                          <path 
                            className="opacity-75" 
                            fill="currentColor" 
                            d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
                          />
                        </svg>
                      )}
                      {isLoading 
                        ? (isEditing ? 'Salvando...' : 'Criando...') 
                        : (isEditing ? 'Salvar' : 'Criar Competição')
                      }
                    </button>
                  </div>
                </form>
              </div>
            </div>
          </div>
        </div>
  );
}

'use client';

/**
 * GameEventsTab - Tab de eventos do jogo
 * 
 * Exibe e permite registrar:
 * - Gols
 * - Cartões (amarelo/vermelho)
 * - Substituições
 * - Timeouts
 * - Outros eventos
 */

import { useState } from 'react';
import { Match, MatchEvent } from '@/context/GamesContext';
import AppCard from '@/components/ui/AppCard';
import AppEmptyState from '@/components/ui/AppEmptyState';
import AppTag from '@/components/ui/AppTag';
import GameEventModal from '../modals/GameEventModal';
import { Plus, Clock, Flag, Hand, ArrowRightLeft, AlertTriangle } from 'lucide-react';

interface GameEventsTabProps {
  game: Match;
}

// Mock de eventos
const MOCK_EVENTS: MatchEvent[] = [
  {
    id: '1',
    match_id: '1',
    event_type: 'goal',
    minute: 5,
    player_name: 'Pedro Santos',
    description: 'Gol de pivô',
  },
  {
    id: '2',
    match_id: '1',
    event_type: 'yellow_card',
    minute: 12,
    player_name: 'Lucas Oliveira',
    description: 'Falta técnica',
  },
  {
    id: '3',
    match_id: '1',
    event_type: 'goal',
    minute: 18,
    player_name: 'Marcos Costa',
    description: 'Contra-ataque',
  },
  {
    id: '4',
    match_id: '1',
    event_type: 'timeout',
    minute: 25,
    description: 'Timeout técnico',
  },
  {
    id: '5',
    match_id: '1',
    event_type: 'substitution',
    minute: 30,
    player_name: 'Carlos Neto',
    description: 'Entra Carlos, sai Pedro',
  },
];

const EVENT_CONFIG = {
  goal: {
    icon: Flag,
    color: 'green' as const,
    label: 'Gol',
    bgColor: 'bg-green-100 dark:bg-green-900/30',
    iconColor: 'text-green-600 dark:text-green-400',
  },
  yellow_card: {
    icon: AlertTriangle,
    color: 'yellow' as const,
    label: 'Cartão Amarelo',
    bgColor: 'bg-yellow-100 dark:bg-yellow-900/30',
    iconColor: 'text-yellow-600 dark:text-yellow-400',
  },
  red_card: {
    icon: AlertTriangle,
    color: 'red' as const,
    label: 'Cartão Vermelho',
    bgColor: 'bg-red-100 dark:bg-red-900/30',
    iconColor: 'text-red-600 dark:text-red-400',
  },
  substitution: {
    icon: ArrowRightLeft,
    color: 'blue' as const,
    label: 'Substituição',
    bgColor: 'bg-blue-100 dark:bg-blue-900/30',
    iconColor: 'text-blue-600 dark:text-blue-400',
  },
  timeout: {
    icon: Hand,
    color: 'purple' as const,
    label: 'Timeout',
    bgColor: 'bg-purple-100 dark:bg-purple-900/30',
    iconColor: 'text-purple-600 dark:text-purple-400',
  },
  other: {
    icon: Clock,
    color: 'gray' as const,
    label: 'Outro',
    bgColor: 'bg-gray-100 dark:bg-gray-700',
    iconColor: 'text-gray-600 dark:text-gray-400',
  },
};

export default function GameEventsTab({ game }: GameEventsTabProps) {
  const [events, setEvents] = useState<MatchEvent[]>(MOCK_EVENTS);
  const [isEventModalOpen, setIsEventModalOpen] = useState(false);
  const [filterType, setFilterType] = useState<string | null>(null);

  const canAddEvents = game.status !== 'Cancelado';

  const filteredEvents = filterType
    ? events.filter((e) => e.event_type === filterType)
    : events;

  const sortedEvents = [...filteredEvents].sort((a, b) => (a.minute || 0) - (b.minute || 0));

  // Estatísticas de eventos
  const eventStats = {
    goals: events.filter((e) => e.event_type === 'goal').length,
    yellowCards: events.filter((e) => e.event_type === 'yellow_card').length,
    redCards: events.filter((e) => e.event_type === 'red_card').length,
    substitutions: events.filter((e) => e.event_type === 'substitution').length,
  };

  const handleAddEvent = (newEvent: MatchEvent) => {
    setEvents([...events, { ...newEvent, id: String(events.length + 1) }]);
    setIsEventModalOpen(false);
  };

  return (
    <div className="p-6">
      {/* Header */}
      <div className="mb-6 flex flex-wrap items-center justify-between gap-4">
        <div>
          <h3 className="text-lg font-medium text-gray-900 dark:text-white">
            Linha do Tempo
          </h3>
          <p className="text-sm text-gray-500 dark:text-gray-400">
            {events.length} eventos registrados
          </p>
        </div>

        {canAddEvents && (
          <button
            onClick={() => setIsEventModalOpen(true)}
            className="flex items-center gap-2 rounded-lg bg-blue-600 px-4 py-2 text-sm font-medium text-white transition-colors hover:bg-blue-700"
          >
            <Plus className="h-4 w-4" />
            Adicionar Evento
          </button>
        )}
      </div>

      {/* Cards de estatísticas */}
      <div className="mb-6 grid gap-4 sm:grid-cols-2 lg:grid-cols-4">
        <button
          onClick={() => setFilterType(filterType === 'goal' ? null : 'goal')}
          className={`rounded-lg border p-4 text-left transition-all ${
            filterType === 'goal'
              ? 'border-green-500 bg-green-50 dark:bg-green-900/20'
              : 'border-gray-200 bg-white hover:border-green-300 dark:border-gray-700 dark:bg-gray-800'
          }`}
        >
          <p className="text-2xl font-bold text-green-600 dark:text-green-400">
            {eventStats.goals}
          </p>
          <p className="text-sm text-gray-600 dark:text-gray-400">Gols</p>
        </button>

        <button
          onClick={() => setFilterType(filterType === 'yellow_card' ? null : 'yellow_card')}
          className={`rounded-lg border p-4 text-left transition-all ${
            filterType === 'yellow_card'
              ? 'border-yellow-500 bg-yellow-50 dark:bg-yellow-900/20'
              : 'border-gray-200 bg-white hover:border-yellow-300 dark:border-gray-700 dark:bg-gray-800'
          }`}
        >
          <p className="text-2xl font-bold text-yellow-600 dark:text-yellow-400">
            {eventStats.yellowCards}
          </p>
          <p className="text-sm text-gray-600 dark:text-gray-400">Cartões Amarelos</p>
        </button>

        <button
          onClick={() => setFilterType(filterType === 'red_card' ? null : 'red_card')}
          className={`rounded-lg border p-4 text-left transition-all ${
            filterType === 'red_card'
              ? 'border-red-500 bg-red-50 dark:bg-red-900/20'
              : 'border-gray-200 bg-white hover:border-red-300 dark:border-gray-700 dark:bg-gray-800'
          }`}
        >
          <p className="text-2xl font-bold text-red-600 dark:text-red-400">
            {eventStats.redCards}
          </p>
          <p className="text-sm text-gray-600 dark:text-gray-400">Cartões Vermelhos</p>
        </button>

        <button
          onClick={() => setFilterType(filterType === 'substitution' ? null : 'substitution')}
          className={`rounded-lg border p-4 text-left transition-all ${
            filterType === 'substitution'
              ? 'border-blue-500 bg-blue-50 dark:bg-blue-900/20'
              : 'border-gray-200 bg-white hover:border-blue-300 dark:border-gray-700 dark:bg-gray-800'
          }`}
        >
          <p className="text-2xl font-bold text-blue-600 dark:text-blue-400">
            {eventStats.substitutions}
          </p>
          <p className="text-sm text-gray-600 dark:text-gray-400">Substituições</p>
        </button>
      </div>

      {/* Filtro ativo */}
      {filterType && (
        <div className="mb-4 flex items-center gap-2">
          <span className="text-sm text-gray-500 dark:text-gray-400">Filtro:</span>
          <AppTag
            label={EVENT_CONFIG[filterType as keyof typeof EVENT_CONFIG]?.label || filterType}
            color={EVENT_CONFIG[filterType as keyof typeof EVENT_CONFIG]?.color || 'gray'}
            onRemove={() => setFilterType(null)}
          />
        </div>
      )}

      {/* Lista de eventos */}
      {sortedEvents.length === 0 ? (
        <AppEmptyState
          icon={<Clock className="h-12 w-12" />}
          title="Nenhum evento registrado"
          description={
            game.status === 'Agendado'
              ? 'Os eventos serão registrados durante o jogo'
              : 'Não há eventos para este jogo'
          }
          action={
            canAddEvents
              ? {
                  label: 'Adicionar evento',
                  onClick: () => setIsEventModalOpen(true),
                }
              : undefined
          }
        />
      ) : (
        <AppCard>
          <div className="relative space-y-0">
            {/* Linha vertical da timeline */}
            <div className="absolute bottom-0 left-6 top-0 w-0.5 bg-gray-200 dark:bg-gray-700" />

            {sortedEvents.map((event, index) => {
              const config = EVENT_CONFIG[event.event_type as keyof typeof EVENT_CONFIG] || EVENT_CONFIG.other;
              const Icon = config.icon;

              return (
                <div
                  key={event.id}
                  className={`relative flex gap-4 pb-6 ${index === sortedEvents.length - 1 ? 'pb-0' : ''}`}
                >
                  {/* Ícone na timeline */}
                  <div className={`relative z-10 flex h-12 w-12 flex-shrink-0 items-center justify-center rounded-full ${config.bgColor}`}>
                    <Icon className={`h-5 w-5 ${config.iconColor}`} />
                  </div>

                  {/* Conteúdo do evento */}
                  <div className="flex-1 pt-1">
                    <div className="flex items-start justify-between">
                      <div>
                        <div className="flex items-center gap-2">
                          <span className="font-medium text-gray-900 dark:text-white">
                            {config.label}
                          </span>
                          {event.minute !== undefined && (
                            <span className="text-sm text-gray-500 dark:text-gray-400">
                              {event.minute}'
                            </span>
                          )}
                        </div>
                        {event.player_name && (
                          <p className="text-sm font-medium text-gray-700 dark:text-gray-300">
                            {event.player_name}
                          </p>
                        )}
                        {event.description && (
                          <p className="mt-1 text-sm text-gray-500 dark:text-gray-400">
                            {event.description}
                          </p>
                        )}
                      </div>
                      <AppTag label={config.label} color={config.color} size="sm" />
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </AppCard>
      )}

      {/* Modal de adicionar evento */}
      <GameEventModal
        isOpen={isEventModalOpen}
        onClose={() => setIsEventModalOpen(false)}
        matchId={game.id}
        onSuccess={handleAddEvent}
      />
    </div>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { Cross2Icon, MagnifyingGlassIcon, ReloadIcon } from '@radix-ui/react-icons';
import { teamsService } from '@/lib/api/teams';

// Mapeamento de categorias de handebol
const CATEGORY_NAMES: Record<number, string> = {
  1: 'Mirim',
  2: 'Infantil',
  3: 'Cadete',
  4: 'Juvenil',
  5: 'Júnior',
  6: 'Adulto',
  7: 'Master',
};

interface Athlete {
  id: string;
  name: string;
  number?: number;
  position?: string;
  photo_url?: string;
}

interface AddAthletesToTeamModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSuccess: () => void;
  teamId: string;
  teamGender: string;      // Obrigatório
  teamCategoryId: number;  // Obrigatório
}

const AddAthletesToTeamModal: React.FC<AddAthletesToTeamModalProps> = ({
  isOpen,
  onClose,
  onSuccess,
  teamId,
  teamGender = 'masculino',
  teamCategoryId
}) => {
  const [searchQuery, setSearchQuery] = useState('');
  const [positionFilter, setPositionFilter] = useState<string>('');
  const [defensivePositionFilter, setDefensivePositionFilter] = useState<string>('');
  const [athletes, setAthletes] = useState<Athlete[]>([]);
  const [selectedAthletes, setSelectedAthletes] = useState<Set<string>>(new Set());
  const [isLoading, setIsLoading] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState('');

  // Buscar atletas disponíveis ao abrir o modal
  useEffect(() => {
    if (isOpen) {
      // Resetar filtros ao abrir
      setSearchQuery('');
      setPositionFilter('');
      setDefensivePositionFilter('');
      setSelectedAthletes(new Set());
    }
  }, [isOpen]);

  // Listener para ESC e Enter
  useEffect(() => {
    if (!isOpen) return;

    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        e.preventDefault();
        handleClose();
      } else if (e.key === 'Enter' && !isSubmitting && selectedAthletes.size > 0) {
        e.preventDefault();
        handleAddAthletes();
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isOpen, isSubmitting, selectedAthletes.size]);

  const fetchAvailableAthletes = async () => {
    try {
      setIsLoading(true);
      setError('');
      
      console.log('🔍 [AddAthletesModal] Filtrando atletas:', {
        teamId,
        teamGender,
        teamCategoryId: teamCategoryId || 'NÃO INFORMADA',
        teamCategoryName: teamCategoryId ? CATEGORY_NAMES[teamCategoryId] : 'N/A',
        searchQuery
      });

      if (!teamCategoryId) {
        console.error('❌ [AddAthletesModal] ERRO GRAVE: teamCategoryId não foi passado ao modal!');
        console.error('   Isso vai prejudicar filtros, relatórios e estatísticas.');
      }
      
      // Buscar atletas disponíveis usando o teamsService com filtros
      const response = await teamsService.getAvailableAthletes({
        page: 1,
        limit: 100,
        search: searchQuery || undefined,
        gender: teamGender || undefined,
        excludeTeamId: teamId,
        teamCategoryId: teamCategoryId, // Filtro automático no backend
      });
      
      console.log('✅ [AddAthletesModal] Atletas retornados:', response.items?.length || 0);

      setAthletes(response.items || []);
    } catch (err) {
      console.error('Erro ao buscar atletas:', err);
      setError('Não foi possível carregar a lista de atletas');
    } finally {
      setIsLoading(false);
    }
  };

  // Recarregar quando filtros mudarem
  useEffect(() => {
    if (isOpen) {
      fetchAvailableAthletes();
    }
  }, [isOpen, searchQuery, positionFilter, defensivePositionFilter]);

  const toggleAthleteSelection = (athleteId: string) => {
    const newSelection = new Set(selectedAthletes);
    if (newSelection.has(athleteId)) {
      newSelection.delete(athleteId);
    } else {
      newSelection.add(athleteId);
    }
    setSelectedAthletes(newSelection);
  };

  const handleAddAthletes = async () => {
    if (selectedAthletes.size === 0) return;

    try {
      setIsSubmitting(true);
      setError('');

      // Adicionar cada atleta selecionado à equipe usando teamsService
      const promises = Array.from(selectedAthletes).map(personId =>
        teamsService.addAthleteToTeam(teamId, personId)
      );

      await Promise.all(promises);

      onSuccess();
      handleClose();
    } catch (err) {
      console.error('Erro ao adicionar atletas:', err);
      setError('Erro ao adicionar atletas. Tente novamente.');
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleClose = () => {
    setSearchQuery('');
    setPositionFilter('');
    setDefensivePositionFilter('');
    setSelectedAthletes(new Set());
    setError('');
    onClose();
  };

  const filteredAthletes = athletes; // Filtragem já feita no backend
  const selectedCountLabel = selectedAthletes.size > 0 ? ` (${selectedAthletes.size})` : '';

  const getInitials = (name: string) => {
    if (!name) return '??';
    const parts = name.trim().split(/\s+/);
    if (parts.length >= 2) {
      // Primeira letra do primeiro nome + primeira letra do último nome
      return `${parts[0][0]}${parts[parts.length - 1][0]}`.toUpperCase();
    }
    // Se só tem um nome, usa as duas primeiras letras
    return name.substring(0, 2).toUpperCase();
  };

  const getAthleteName = (athlete: any) => {
    return athlete.full_name || athlete.name || 'Sem nome';
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      {/* Backdrop */}
      <div
        className="absolute inset-0 bg-black/50 backdrop-blur-sm"
        onClick={handleClose}
      />

      {/* Modal */}
      <div className="relative bg-white dark:bg-[#111] rounded-lg shadow-2xl w-full max-w-xl border border-slate-200 dark:border-slate-800 max-h-[90vh] flex flex-col overflow-hidden">
        {/* Header */}
        <div className="flex items-center justify-between px-6 py-5 border-b border-slate-200 dark:border-slate-800 bg-white dark:bg-[#111]">
          <h2 className="text-[18px] font-heading font-bold text-slate-900 dark:text-white tracking-tight">
            Adicione Atletas na sua Equipe
          </h2>
          <button
            onClick={handleClose}
            className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 transition-colors rounded-sm p-0.5"
            disabled={isSubmitting}
          >
            <Cross2Icon className="w-5 h-5" />
          </button>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-6">
          {/* Elenco Section */}
          <div className="space-y-4">
            <div>
              <label className="block text-[14px] font-bold text-slate-900 dark:text-white mb-2">
                Elenco
              </label>
              <p className="text-[12px] text-slate-500 dark:text-slate-400 mt-0.5 mb-3">
                Selecione os atletas disponíveis
              </p>

              {/* Informações da Equipe (readonly) */}
              <div className="grid grid-cols-2 gap-5 mb-3">
                {/* Gênero da Equipe */}
                <div className="space-y-1.5">
                  <label className="block text-[13px] font-semibold text-slate-700 dark:text-slate-300">
                    Gênero da Equipe
                  </label>
                  <input
                    type="text"
                    value={teamGender === 'masculino' ? 'Masculino' : 'Feminino'}
                    disabled
                    className="block w-full rounded-sm border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-900/50 text-[13px] text-slate-500 cursor-not-allowed"
                  />
                </div>

                {/* Categoria da Equipe */}
                <div className="space-y-1.5">
                  <label className="block text-[13px] font-semibold text-slate-700 dark:text-slate-300">
                    Categoria da Equipe
                  </label>
                  <input
                    type="text"
                    value={teamCategoryId ? CATEGORY_NAMES[teamCategoryId] || `Categoria ${teamCategoryId}` : 'Não informada'}
                    disabled
                    className="block w-full rounded-sm border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-900/50 text-[13px] text-slate-500 cursor-not-allowed"
                  />
                </div>
              </div>

              {/* Filtros de Posição */}
              <div className="grid grid-cols-2 gap-3 mb-3">
                <div>
                  <label className="block text-xs font-medium text-slate-600 dark:text-slate-400 mb-1">
                    Posição Ofensiva
                  </label>
                  <select
                    value={positionFilter}
                    onChange={(e) => setPositionFilter(e.target.value)}
                    className="w-full px-3 py-2 text-sm bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none"
                  >
                    <option value="">Todas</option>
                    <option value="armador">Armador</option>
                    <option value="ponta_esquerda">Ponta Esquerda</option>
                    <option value="ponta_direita">Ponta Direita</option>
                    <option value="pivo">Pivô</option>
                  </select>
                </div>

                <div>
                  <label className="block text-xs font-medium text-slate-600 dark:text-slate-400 mb-1">
                    Posição Defensiva
                  </label>
                  <select
                    value={defensivePositionFilter}
                    onChange={(e) => setDefensivePositionFilter(e.target.value)}
                    className="w-full px-3 py-2 text-sm bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none"
                  >
                    <option value="">Todas</option>
                    <option value="goleiro">Goleiro</option>
                    <option value="fixo">Fixo</option>
                    <option value="lateral">Lateral</option>
                  </select>
                </div>
              </div>

              <div className="flex items-center justify-end mb-3">
                {selectedAthletes.size > 0 && (
                  <span className="text-[11px] font-mono text-slate-500 dark:text-slate-400 bg-slate-100 dark:bg-slate-800 px-2 py-0.5 rounded-sm border border-slate-200 dark:border-slate-700 font-bold">
                    {selectedAthletes.size} Selecionado{selectedAthletes.size > 1 ? 's' : ''}
                  </span>
                )}
              </div>

              {/* Search */}
              <div className="relative mb-3 group">
                <MagnifyingGlassIcon className="absolute left-3 top-1/2 -translate-y-1/2 w-[18px] h-[18px] text-slate-400 group-focus-within:text-slate-600 transition-colors" />
                <input
                  type="text"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  placeholder="Buscar atleta por nome ou ID..."
                  className="block w-full rounded-sm border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-[#0a0a0a] pl-9 py-2 text-[13px] text-slate-900 dark:text-white placeholder-slate-400 focus:border-slate-400 dark:focus:border-slate-500 focus:ring-0 focus:bg-white transition-all"
                />
              </div>

              {/* Athletes List with Loading Inside */}
              <div className="border border-slate-200 dark:border-slate-800 rounded-sm overflow-hidden flex flex-col h-[280px]">
                {isLoading ? (
                  <div className="flex flex-col items-center justify-center py-16 bg-white dark:bg-slate-900 space-y-4">
                    <div className="relative w-16 h-16 animate-pulse">
                      <img 
                        src="/images/logo/logo-icon.svg" 
                        alt="HB Track" 
                        className="w-full h-full object-contain dark:hidden"
                      />
                      <img 
                        src="/images/logo/logo-icon-dark.svg" 
                        alt="HB Track" 
                        className="w-full h-full object-contain hidden dark:block"
                      />
                    </div>
                    <div className="w-48 h-1.5 bg-slate-200 dark:bg-slate-800 rounded-full overflow-hidden">
                      <div 
                        className="h-full bg-slate-900 dark:bg-slate-100 rounded-full"
                        style={{ 
                          animation: 'loading-bar 2.5s ease-in-out infinite'
                        }}
                      />
                    </div>
                    <p className="text-xs text-slate-500 dark:text-slate-400 font-medium">Carregando atletas...</p>
                    <style jsx>{`
                      @keyframes loading-bar {
                        0% {
                          width: 0%;
                          margin-left: 0%;
                        }
                        50% {
                          width: 70%;
                          margin-left: 15%;
                        }
                        100% {
                          width: 0%;
                          margin-left: 100%;
                        }
                      }
                    `}</style>
                  </div>
                ) : error ? (
                  <div className="text-center py-12 bg-white dark:bg-slate-900">
                    <p className="text-sm text-red-600 dark:text-red-400 mb-2">{error}</p>
                    <button
                      onClick={fetchAvailableAthletes}
                      className="text-xs font-semibold text-blue-600 dark:text-blue-400 hover:underline"
                    >
                      Tentar novamente
                    </button>
                  </div>
                ) : filteredAthletes.length === 0 ? (
                  <div className="text-center py-12 bg-white dark:bg-slate-900">
                    <p className="text-sm text-slate-500 dark:text-slate-400">
                      Nenhum atleta disponível
                    </p>
                  </div>
                ) : (
                  <div className="overflow-y-auto custom-scrollbar bg-white dark:bg-[#0f0f0f] divide-y divide-slate-100 dark:divide-slate-800">
                    {filteredAthletes.map((athlete) => {
                      const isSelected = selectedAthletes.has(athlete.id);
                      return (
                        <div
                          key={athlete.id}
                          onClick={() => toggleAthleteSelection(athlete.id)}
                          className={`flex items-center gap-3 px-4 py-2.5 cursor-pointer transition-colors ${
                            isSelected
                              ? 'bg-blue-50 dark:bg-blue-950/30'
                              : 'hover:bg-slate-50 dark:hover:bg-slate-800/30'
                          }`}
                        >
                        {/* Avatar */}
                        {athlete.photo_url ? (
                          <img
                            src={athlete.photo_url}
                            alt={athlete.name}
                            className="h-8 w-8 rounded-full bg-slate-200 object-cover border border-slate-100 dark:border-slate-700"
                          />
                        ) : (
                          <div className="h-8 w-8 rounded-full bg-slate-900 dark:bg-slate-100 flex items-center justify-center text-white dark:text-black font-bold text-[10px] border border-slate-100 dark:border-slate-700">
                            {getInitials(getAthleteName(athlete))}
                          </div>
                        )}

                        {/* Info */}
                        <div className="flex-1 min-w-0">
                          <p className="text-[13px] font-semibold text-slate-700 dark:text-slate-200 leading-none">
                            {getAthleteName(athlete)}
                          </p>
                          <p className="text-[11px] font-mono text-slate-400 mt-1">
                            ID: {athlete.number || athlete.id.substring(0, 8)}
                          </p>
                        </div>

                        {/* Ação: + em círculo */}
                        <div
                          className={`w-4 h-4 rounded-full flex items-center justify-center transition-all border ${
                            isSelected
                              ? 'bg-green-500 border-green-500 text-white'
                              : 'border-slate-300 dark:border-slate-600 text-slate-400 dark:text-slate-500 hover:border-slate-400 dark:hover:border-slate-500'
                          }`}
                        >
                          {isSelected ? (
                            <svg className="w-2.5 h-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}>
                              <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
                            </svg>
                          ) : (
                            <svg className="w-2.5 h-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                              <path strokeLinecap="round" strokeLinejoin="round" d="M12 4v16m8-8H4" />
                            </svg>
                          )}
                        </div>
                      </div>
                    );
                  })}
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>

        {/* Footer */}
        <div className="flex items-center justify-end gap-3 px-6 py-4 bg-slate-50 dark:bg-[#151515] border-t border-slate-200 dark:border-slate-800">
          <button
            onClick={handleClose}
            disabled={isSubmitting}
            className="px-4 py-2 text-[13px] font-bold text-slate-600 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white transition-colors disabled:opacity-50"
          >
            Cancelar
          </button>
          <button
            onClick={handleAddAthletes}
            disabled={isSubmitting || selectedAthletes.size === 0}
            className="px-5 py-2 bg-slate-900 dark:bg-slate-100 text-white dark:text-black text-[13px] font-bold rounded-sm shadow-sm hover:bg-slate-800 dark:hover:bg-white transition-colors border border-transparent disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
          >
            {isSubmitting ? (
              <>
                <ReloadIcon className="w-3 h-3 animate-spin" />
                Adicionando...
              </>
            ) : (
              `Adicionar${selectedCountLabel}`
            )}
          </button>
        </div>
      </div>
    </div>
  );
};

export default AddAthletesToTeamModal;

'use client';

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Cross2Icon, ReloadIcon, GearIcon, InfoCircledIcon, ExclamationTriangleIcon } from '@radix-ui/react-icons';
import { Team } from '@/types/teams-v2';
import { teamsService } from '@/lib/api/teams';
import { useToast } from '@/context/ToastContext';
import { useTeamPermissions } from '@/lib/hooks/useTeamPermissions';

interface ConfigureTeamModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSuccess: (updatedTeam: Team) => void;
  team: Team;
}

// ============================================================================
// CONFIGURAÇÕES
// ============================================================================

const NAME_MIN_LENGTH = 3;
const NAME_MAX_LENGTH = 50;

// ============================================================================
// MAIN COMPONENT
// ============================================================================

const ConfigureTeamModal: React.FC<ConfigureTeamModalProps> = ({
  isOpen,
  onClose,
  onSuccess,
  team,
}) => {
  // Refs
  const nameInputRef = useRef<HTMLInputElement>(null);
  const modalRef = useRef<HTMLDivElement>(null);

  // State
  const [name, setName] = useState(team.name || '');

  // Validation state
  const [nameError, setNameError] = useState('');
  const [hasUnsavedChanges, setHasUnsavedChanges] = useState(false);

  // API state
  const [isSaving, setIsSaving] = useState(false);
  const [apiError, setApiError] = useState<string | null>(null);
  const [showCloseConfirm, setShowCloseConfirm] = useState(false);

  // Hooks
  const { toast } = useToast();
  const { canManageTeam } = useTeamPermissions(team.id);

  // ============================================================================
  // EFFECTS
  // ============================================================================

  // Reset e focus ao abrir
  useEffect(() => {
    if (isOpen) {
      // Reset para valores originais
      setName(team.name || '');
      setNameError('');
      setApiError(null);
      setIsSaving(false);
      setHasUnsavedChanges(false);
      setShowCloseConfirm(false);

      // Auto-focus no campo nome
      setTimeout(() => {
        nameInputRef.current?.focus();
        nameInputRef.current?.select();
      }, 100);
    }
  }, [isOpen, team]);

  // Detectar alterações não salvas
  useEffect(() => {
    const nameChanged = name !== (team.name || '');
    setHasUnsavedChanges(nameChanged);
  }, [name, team]);

  // Validação do nome em tempo real
  useEffect(() => {
    if (name.length === 0) {
      setNameError('');
    } else if (name.trim().length < NAME_MIN_LENGTH) {
      setNameError(`Nome deve ter pelo menos ${NAME_MIN_LENGTH} caracteres`);
    } else if (name.trim().length > NAME_MAX_LENGTH) {
      setNameError(`Nome não pode ter mais de ${NAME_MAX_LENGTH} caracteres`);
    } else {
      setNameError('');
    }
  }, [name]);

  // Keyboard shortcuts
  useEffect(() => {
    if (!isOpen) return;

    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        e.preventDefault();
        handleTryClose();
      } else if (e.key === 'Enter' && (e.metaKey || e.ctrlKey) && isFormValid && !isSaving) {
        e.preventDefault();
        handleSave();
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isOpen, isSaving, name, hasUnsavedChanges]);

  // ============================================================================
  // COMPUTED
  // ============================================================================

  const isFormValid = name.trim().length >= NAME_MIN_LENGTH && 
                      name.trim().length <= NAME_MAX_LENGTH && 
                      nameError === '';

  // ============================================================================
  // HANDLERS
  // ============================================================================

  const handleTryClose = useCallback(() => {
    if (isSaving) return;

    if (hasUnsavedChanges) {
      setShowCloseConfirm(true);
    } else {
      onClose();
    }
  }, [isSaving, hasUnsavedChanges, onClose]);

  const handleConfirmClose = () => {
    setShowCloseConfirm(false);
    onClose();
  };

  const handleCancelClose = () => {
    setShowCloseConfirm(false);
  };

  const handleBackdropClick = (e: React.MouseEvent) => {
    if (e.target === e.currentTarget && !isSaving) {
      handleTryClose();
    }
  };

  const handleSave = async () => {
    if (!isFormValid || isSaving) return;

    // Verificar permissão
    if (!canManageTeam) {
      setApiError('Você não tem permissão para editar esta equipe.');
      return;
    }

    setIsSaving(true);
    setApiError(null);

    try {
      // Preparar dados para atualização
      const updateData = {
        name: name.trim(),
      };

      // Chamar API (método update do teamsService)
      const apiTeam = await teamsService.update(team.id, updateData);

      // Mapear resposta da API para o tipo Team local
      const updatedTeam: Team = {
        ...team,
        name: apiTeam.name,
      };

      // Sucesso - fechar modal e notificar
      toast.success('Equipe atualizada com sucesso!');
      onSuccess(updatedTeam);
      onClose();
    } catch (error: any) {
      console.error('❌ [ConfigureTeamModal] Erro ao salvar:', error);

      // Extrair mensagem de erro
      let errorMessage = 'Não foi possível salvar as alterações.';

      if (error?.response?.data?.detail) {
        errorMessage = error.response.data.detail;
      } else if (error?.message) {
        errorMessage = error.message;
      }

      // Traduzir erros comuns
      if (errorMessage.includes('already exists') || errorMessage.includes('já existe')) {
        errorMessage = 'Já existe uma equipe com esse nome.';
      } else if (errorMessage.includes('permission') || errorMessage.includes('forbidden')) {
        errorMessage = 'Você não tem permissão para editar esta equipe.';
      } else if (errorMessage.includes('500')) {
        errorMessage = 'Erro no servidor. Tente novamente em alguns instantes.';
      } else if (errorMessage.includes('network') || errorMessage.includes('Network')) {
        errorMessage = 'Erro de conexão. Verifique sua internet.';
      }

      setApiError(errorMessage);
    } finally {
      setIsSaving(false);
    }
  };

  const handleRetry = () => {
    setApiError(null);
    handleSave();
  };

  // ============================================================================
  // RENDER
  // ============================================================================

  if (!isOpen) return null;

  return (
    <div 
      className="fixed inset-0 z-[60] flex items-center justify-center p-4"
      onClick={handleBackdropClick}
    >
      {/* Backdrop */}
      <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" />

      {/* Modal */}
      <div 
        ref={modalRef}
        className="relative w-full max-w-md bg-white dark:bg-[#0f0f0f] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200 border border-slate-200 dark:border-slate-800 rounded-lg"
        onClick={(e) => e.stopPropagation()}
      >
        {/* Diálogo de confirmação de fechamento */}
        {showCloseConfirm && (
          <div className="absolute inset-0 z-10 bg-white dark:bg-[#0f0f0f] flex flex-col items-center justify-center p-8 animate-in fade-in duration-200">
            <div className="w-12 h-12 bg-amber-100 dark:bg-amber-900/30 rounded-full flex items-center justify-center mb-4">
              <ExclamationTriangleIcon className="w-6 h-6 text-amber-600 dark:text-amber-400" />
            </div>
            <h3 className="text-lg font-heading font-bold text-slate-900 dark:text-white mb-2">
              Descartar alterações?
            </h3>
            <p className="text-sm text-slate-500 dark:text-slate-400 text-center mb-6">
              Você tem alterações não salvas. Deseja realmente sair?
            </p>
            <div className="flex gap-3">
              <button
                onClick={handleCancelClose}
                className="px-4 py-2 text-sm font-semibold text-slate-600 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white transition-colors"
              >
                Continuar editando
              </button>
              <button
                onClick={handleConfirmClose}
                className="px-4 py-2 bg-red-600 text-white text-sm font-bold rounded-lg hover:bg-red-700 transition-colors"
              >
                Descartar
              </button>
            </div>
          </div>
        )}

        {/* Header */}
        <div className="flex items-center justify-between px-5 py-4 border-b border-slate-200 dark:border-slate-800">
          <div className="flex items-center gap-3">
            <div className="w-8 h-8 bg-slate-100 dark:bg-slate-800 rounded-lg flex items-center justify-center">
              <GearIcon className="w-4 h-4 text-slate-600 dark:text-slate-400" />
            </div>
            <h2 className="text-lg font-heading font-bold tracking-tight text-slate-900 dark:text-white">
              Configurar Equipe
            </h2>
          </div>
          <button
            onClick={handleTryClose}
            disabled={isSaving}
            className="p-1.5 hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-400 transition-colors rounded disabled:opacity-50 disabled:cursor-not-allowed"
            aria-label="Fechar modal"
            title="Fechar (Esc)"
          >
            <Cross2Icon className="w-4 h-4" />
          </button>
        </div>

        {/* Content */}
        <form 
          onSubmit={(e) => { e.preventDefault(); handleSave(); }}
          className="p-5 space-y-5"
        >
          {/* Erro da API */}
          {apiError && (
            <div className="p-3 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-lg animate-in fade-in slide-in-from-top-2 duration-300">
              <div className="flex items-start gap-3">
                <ExclamationTriangleIcon className="w-4 h-4 text-red-500 mt-0.5 flex-shrink-0" />
                <div className="flex-1 space-y-2">
                  <p className="text-sm text-red-700 dark:text-red-300 font-medium">{apiError}</p>
                  <button
                    type="button"
                    onClick={handleRetry}
                    className="flex items-center gap-1.5 text-xs font-semibold text-red-600 dark:text-red-400 hover:underline"
                  >
                    <ReloadIcon className="w-3 h-3" />
                    Tentar novamente
                  </button>
                </div>
              </div>
            </div>
          )}

          {/* Nome da equipe */}
          <div className="space-y-1.5">
            <label className="text-xs font-semibold text-slate-700 dark:text-slate-300">
              Nome da equipe <span className="text-red-500">*</span>
            </label>
            <input
              ref={nameInputRef}
              type="text"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="Ex: Sub-17 Masculino"
              maxLength={NAME_MAX_LENGTH}
              disabled={isSaving}
              className={`w-full px-3 py-2.5 text-sm bg-white dark:bg-slate-950 border rounded-lg transition-all ${
                nameError
                  ? 'border-red-500 dark:border-red-500 focus:ring-red-500'
                  : 'border-slate-200 dark:border-slate-800 focus:ring-slate-900 dark:focus:ring-slate-100'
              } focus:ring-1 outline-none disabled:opacity-50 disabled:cursor-not-allowed`}
              aria-invalid={!!nameError}
            />
            <div className="flex items-center justify-between">
              {nameError ? (
                <p className="text-[10px] text-red-500 font-medium">{nameError}</p>
              ) : (
                <p className="text-[10px] text-slate-400">
                  {NAME_MIN_LENGTH}-{NAME_MAX_LENGTH} caracteres
                </p>
              )}
              <span className={`text-[10px] ${
                name.length > NAME_MAX_LENGTH ? 'text-red-500' : 'text-slate-400'
              }`}>
                {name.length}/{NAME_MAX_LENGTH}
              </span>
            </div>
          </div>

          {/* Campos somente leitura */}
          <div className="grid grid-cols-2 gap-3">
            <div className="space-y-1.5">
              <label className="text-xs font-semibold text-slate-700 dark:text-slate-300">
                Categoria
              </label>
              <input
                type="text"
                value={team.category || 'Não definida'}
                disabled
                className="w-full px-3 py-2 text-sm bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-800 rounded-lg text-slate-500 dark:text-slate-400 cursor-not-allowed"
              />
            </div>
            <div className="space-y-1.5">
              <label className="text-xs font-semibold text-slate-700 dark:text-slate-300">
                Gênero
              </label>
              <input
                type="text"
                value={team.gender || 'Não definido'}
                disabled
                className="w-full px-3 py-2 text-sm bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-800 rounded-lg text-slate-500 dark:text-slate-400 cursor-not-allowed capitalize"
              />
            </div>
          </div>

          {/* Info box */}
          <div className="flex items-start gap-2 p-3 bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-800 rounded-lg">
            <InfoCircledIcon className="w-4 h-4 text-slate-400 mt-0.5 flex-shrink-0" />
            <p className="text-[10px] text-slate-500 dark:text-slate-400">
              Alterações serão aplicadas imediatamente a todos os membros da equipe.
              Categoria e gênero não podem ser alterados após a criação.
            </p>
          </div>
        </form>

        {/* Footer */}
        <div className="px-5 py-3 bg-slate-50 dark:bg-slate-900/50 border-t border-slate-200 dark:border-slate-800 flex items-center justify-between">
          <div className="flex items-center gap-2">
            {hasUnsavedChanges && !isSaving && (
              <span className="text-[10px] text-amber-600 dark:text-amber-400 font-medium animate-in fade-in duration-300">
                • Alterações não salvas
              </span>
            )}
          </div>
          <div className="flex gap-2">
            <button
              type="button"
              onClick={handleTryClose}
              disabled={isSaving}
              className="px-4 py-2 text-xs font-semibold text-slate-500 hover:text-slate-800 dark:hover:text-slate-300 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
            >
              Cancelar
            </button>
            <button
              type="button"
              onClick={handleSave}
              disabled={!isFormValid || isSaving || !hasUnsavedChanges}
              className="px-4 py-2 bg-slate-900 dark:bg-slate-100 text-white dark:text-black text-xs font-bold rounded-lg shadow-sm hover:opacity-90 transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2 min-w-[100px] justify-center"
            >
              {isSaving ? (
                <>
                  <ReloadIcon className="w-3.5 h-3.5 animate-spin" />
                  Salvando...
                </>
              ) : (
                'Salvar alterações'
              )}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ConfigureTeamModal;

'use client';

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Cross2Icon, ReloadIcon, InfoCircledIcon, CheckCircledIcon, PersonIcon } from '@radix-ui/react-icons';
import { Team } from '@/types/teams-v2';
import { teamsService } from '@/lib/api/teams';
import { mapApiTeamToV2 } from '@/lib/adapters/teams-v2-adapter';
import { useAuth } from '@/context/AuthContext';
import { useToast } from '@/context/ToastContext';

interface CreateTeamModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSuccess: (newTeam: Team) => void;
  onError: (message: string) => void;
}

const CreateTeamModal: React.FC<CreateTeamModalProps> = ({ isOpen, onClose, onSuccess, onError }) => {
  const { user } = useAuth();
  const { toast } = useToast();
  const [teamName, setTeamName] = useState('');
  const [gender, setGender] = useState('');
  const [category, setCategory] = useState('');
  const [isCreating, setIsCreating] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);
  const [createdTeamName, setCreatedTeamName] = useState('');
  const [validationError, setValidationError] = useState('');
  const [genderError, setGenderError] = useState('');
  const [categoryError, setCategoryError] = useState('');
  const [showCloseConfirm, setShowCloseConfirm] = useState(false);

  // Refs para foco
  const nameInputRef = useRef<HTMLInputElement>(null);
  const modalRef = useRef<HTMLDivElement>(null);

  // Verificar se há dados não salvos
  const hasUnsavedData = teamName.trim() !== '' || gender !== '' || category !== '';

  // Reset form ao abrir modal
  useEffect(() => {
    if (isOpen) {
      setTeamName('');
      setGender('');
      setCategory('');
      setValidationError('');
      setGenderError('');
      setCategoryError('');
      setIsCreating(false);
      setShowSuccess(false);
      setCreatedTeamName('');
      setShowCloseConfirm(false);

      // Foco automático no campo de nome após animação
      setTimeout(() => {
        nameInputRef.current?.focus();
      }, 100);
    }
  }, [isOpen]);

  // Validação em tempo real
  useEffect(() => {
    if (teamName.length === 0) {
      setValidationError('');
    } else if (teamName.trim().length < 3) {
      setValidationError('O nome deve ter no mínimo 3 caracteres');
    } else {
      setValidationError('');
    }
  }, [teamName]);

  // Handler para tentar fechar com confirmação
  const handleTryClose = useCallback(() => {
    if (isCreating) return;

    if (hasUnsavedData) {
      setShowCloseConfirm(true);
    } else {
      onClose();
    }
  }, [isCreating, hasUnsavedData, onClose]);

  // Eventos de teclado
  useEffect(() => {
    if (!isOpen) return;

    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape' && !isCreating) {
        if (showCloseConfirm) {
          setShowCloseConfirm(false);
        } else {
          handleTryClose();
        }
      } else if (e.key === 'Enter' && !isCreating && isFormValid && !showCloseConfirm) {
        handleCreateTeam();
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isOpen, isCreating, teamName, showCloseConfirm, handleTryClose]);

  const isFormValid = teamName.trim().length >= 3 && validationError === '' && gender !== '' && category !== '';

  const handleCreateTeam = async () => {
    if (!isFormValid || isCreating) return;

    setIsCreating(true);

    try {
      // O select já retorna valores corretos:
      // category vem como string "1", "2", "3", etc.
      // gender vem como "masculino" ou "feminino"
      const selectedCategoryId = parseInt(category);
      const selectedGender = gender as 'feminino' | 'masculino';

      console.log('🔍 [CreateTeam] Criando equipe:', {
        name: teamName.trim(),
        category_id: selectedCategoryId,
        gender: selectedGender
      });

      // Criar equipe via API - o backend já valida duplicatas
      const apiTeam = await teamsService.create({
        name: teamName.trim(),
        category_id: selectedCategoryId,
        gender: selectedGender,
        is_our_team: true
      });

      // Converter para formato Teams-v2
      const newTeam = mapApiTeamToV2(apiTeam);

      // Guardar nome para exibir no sucesso
      setCreatedTeamName(teamName.trim());

      // Mostrar estado de sucesso
      setShowSuccess(true);

      // Toast de sucesso
      toast.success('Equipe criada com sucesso!', {
        description: `${teamName.trim()} está pronta para receber membros.`
      });

      // Aguardar um pouco e então fechar + callback
      setTimeout(() => {
        onClose();
        onSuccess(newTeam);
      }, 800);

    } catch (error) {
      console.error('❌ Erro ao criar equipe:', error);
      let errorMessage = 'Não foi possível criar a equipe. Tente novamente.';

      // Extrair mensagem de erro do backend
      if (error && typeof error === 'object') {
        const err = error as any;
        if (err.response?.data?.detail) {
          const detail = err.response.data.detail;
          errorMessage = typeof detail === 'string' ? detail : detail.message || errorMessage;
        } else if (err.message) {
          errorMessage = err.message;
        }
      }

      setValidationError(errorMessage);
      onError(errorMessage);
    } finally {
      setIsCreating(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-4" style={{ top: 0, left: 0, right: 0, bottom: 0 }}>
      {/* Dialog de confirmação de fechamento */}
      {showCloseConfirm && (
        <div className="fixed inset-0 z-[70] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/60" onClick={() => setShowCloseConfirm(false)} />
          <div className="relative w-full max-w-sm bg-white dark:bg-[#0f0f0f] shadow-2xl rounded-lg overflow-hidden animate-in zoom-in-95 duration-200 border border-slate-200 dark:border-slate-800">
            <div className="p-5 text-center">
              <div className="w-12 h-12 mx-auto mb-4 bg-amber-100 dark:bg-amber-900/30 rounded-full flex items-center justify-center">
                <InfoCircledIcon className="w-6 h-6 text-amber-600 dark:text-amber-400" />
              </div>
              <h3 className="text-base font-bold text-slate-900 dark:text-white mb-2">
                Descartar alterações?
              </h3>
              <p className="text-sm text-slate-500 dark:text-slate-400">
                Você tem dados não salvos. Deseja realmente fechar sem criar a equipe?
              </p>
            </div>
            <div className="px-5 py-3 bg-slate-50 dark:bg-slate-900/50 border-t border-slate-200 dark:border-slate-800 flex justify-end gap-2">
              <button
                onClick={() => setShowCloseConfirm(false)}
                className="px-4 py-2 text-xs font-semibold text-slate-600 hover:text-slate-800 dark:hover:text-slate-300 transition-colors"
              >
                Continuar editando
              </button>
              <button
                onClick={() => {
                  setShowCloseConfirm(false);
                  onClose();
                }}
                className="px-4 py-2 bg-red-600 text-white text-xs font-bold rounded-lg hover:bg-red-700 transition-all"
              >
                Descartar
              </button>
            </div>
          </div>
        </div>
      )}

      <div 
        className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" 
        onClick={handleTryClose}
      ></div>
      <div 
        ref={modalRef} 
        data-testid="create-team-modal"
        className="relative w-full max-w-lg bg-white dark:bg-[#0f0f0f] shadow-2xl rounded-lg overflow-hidden animate-in zoom-in-95 duration-200 border border-slate-200 dark:border-slate-800"
      >
        {/* Estado de sucesso */}
        {showSuccess ? (
          <div className="flex flex-col items-center justify-center py-16 space-y-4 animate-in zoom-in-95 duration-300">
            <div className="w-16 h-16 bg-emerald-100 dark:bg-emerald-900/30 rounded-full flex items-center justify-center">
              <CheckCircledIcon className="w-8 h-8 text-emerald-600 dark:text-emerald-400" />
            </div>
            <div className="text-center">
              <p className="text-lg font-bold text-slate-900 dark:text-white">Equipe criada!</p>
              <p className="text-sm text-slate-500 dark:text-slate-400 mt-1">{createdTeamName}</p>
            </div>
          </div>
        ) : isCreating ? (
          <div className="flex flex-col items-center justify-center py-20 space-y-4">
            <div className="relative w-16 h-16 animate-pulse">
              <img 
                src="/images/logo/logo-icon.svg" 
                alt="HB Track" 
                className="w-full h-full object-contain dark:hidden"
              />
              <img 
                src="/images/logo/logo-icon-dark.svg" 
                alt="HB Track" 
                className="w-full h-full object-contain hidden dark:block"
              />
            </div>
            <div className="w-48 h-1.5 bg-slate-200 dark:bg-slate-800 rounded-full overflow-hidden">
              <div 
                className="h-full bg-slate-900 dark:bg-slate-100 rounded-full"
                style={{ 
                  animation: 'loading-bar 2.5s ease-in-out infinite'
                }}
              />
            </div>
            <p className="text-xs text-slate-500 dark:text-slate-400 font-medium">Criando equipe...</p>
            <style jsx>{`
              @keyframes loading-bar {
                0% { width: 0%; margin-left: 0%; }
                50% { width: 70%; margin-left: 15%; }
                100% { width: 0%; margin-left: 100%; }
              }
            `}</style>
          </div>
        ) : (
        <>
        <div className="flex items-center justify-between px-5 py-4 border-b border-slate-200 dark:border-slate-800">
          <div className="flex items-center gap-3">
            <div className="w-8 h-8 bg-slate-100 dark:bg-slate-800 rounded-lg flex items-center justify-center">
              <PersonIcon className="w-4 h-4 text-slate-600 dark:text-slate-400" />
            </div>
            <h2 className="text-lg font-heading font-bold tracking-tight text-slate-900 dark:text-white">Criar nova equipe</h2>
          </div>
          <button 
            onClick={handleTryClose} 
            data-testid="close-modal-btn"
            className="p-1.5 hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-400 rounded transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
            aria-label="Fechar modal"
            title="Fechar (Esc)"
            disabled={isCreating}
          >
            <Cross2Icon className="w-4 h-4" />
          </button>
        </div>

        <form onSubmit={(e) => { e.preventDefault(); handleCreateTeam(); }} className="p-5 space-y-4">
          <div className="space-y-1.5">
            <label htmlFor="team-name" className="text-xs font-semibold text-slate-700 dark:text-slate-300">
              Nome da equipe <span className="text-red-500">*</span>
            </label>
            <input
              ref={nameInputRef}
              id="team-name"
              type="text"
              value={teamName}
              onChange={(e) => setTeamName(e.target.value)}
              placeholder="Ex: Sub-17, Feminino Elite, Técnico João"
              data-testid="team-name-input"
              className={`w-full px-3 py-2.5 text-sm bg-white dark:bg-slate-950 border rounded-lg ${
                validationError 
                  ? 'border-red-500 dark:border-red-500 focus:ring-red-500' 
                  : 'border-slate-200 dark:border-slate-800 focus:ring-slate-900 dark:focus:ring-slate-100'
              } focus:ring-2 focus:ring-offset-0 outline-none transition-all disabled:opacity-50 disabled:cursor-not-allowed`}
              disabled={isCreating}
              aria-invalid={!!validationError}
              aria-describedby={validationError ? 'name-error' : 'name-help'}
            />
            {validationError ? (
              <p id="name-error" data-testid="team-name-error" className="text-[10px] text-red-500 font-medium">{validationError}</p>
            ) : (
              <p id="name-help" className="text-[10px] text-slate-400">O nome deve ser único para facilitar a identificação nos relatórios.</p>
            )}
          </div>

          <div className="space-y-1.5">
            <label className="text-xs font-semibold text-slate-700 dark:text-slate-300">
              Gênero <span className="text-red-500">*</span>
            </label>
            <select 
              value={gender}
              onChange={(e) => setGender(e.target.value)}
              data-testid="team-gender-select"
              className={`w-full px-3 py-2 text-xs bg-white dark:bg-slate-950 border ${
                genderError
                  ? 'border-red-500 dark:border-red-500'
                  : 'border-slate-200 dark:border-slate-800'
              } outline-none cursor-pointer disabled:opacity-50 disabled:cursor-not-allowed`}
              disabled={isCreating}
              aria-invalid={!!genderError}
            >
              <option value="">Selecione o gênero...</option>
              <option value="masculino">Masculino</option>
              <option value="feminino">Feminino</option>
            </select>
            {genderError && (
              <p data-testid="team-gender-error" className="text-[10px] text-red-500 font-medium">{genderError}</p>
            )}
          </div>

          <div className="space-y-1.5">
            <label className="text-xs font-semibold text-slate-700 dark:text-slate-300">
              Categoria <span className="text-red-500">*</span>
            </label>
            <select 
              value={category}
              onChange={(e) => setCategory(e.target.value)}
              data-testid="team-category-select"
              className={`w-full px-3 py-2 text-xs bg-white dark:bg-slate-950 border ${
                categoryError
                  ? 'border-red-500 dark:border-red-500'
                  : 'border-slate-200 dark:border-slate-800'
              } outline-none cursor-pointer disabled:opacity-50 disabled:cursor-not-allowed`}
              disabled={isCreating}
              aria-invalid={!!categoryError}
            >
              <option value="">Selecione uma categoria...</option>
              <option value="1">Mirim</option>
              <option value="2">Infantil</option>
              <option value="3">Cadete</option>
              <option value="4">Juvenil</option>
              <option value="5">Júnior</option>
              <option value="6">Adulto</option>
              <option value="7">Master</option>
            </select>
            {categoryError && (
              <p data-testid="team-category-error" className="text-[10px] text-red-500 font-medium">{categoryError}</p>
            )}
          </div>

          <div className="grid grid-cols-2 gap-3">
            <div className="space-y-1.5">
              <label className="text-xs font-semibold text-slate-700 dark:text-slate-300">Clube (Organização)</label>
              <input
                type="text"
