    placement: 'right',
  },
];

// ================================================================================
// STYLES
// ================================================================================

const tourStyles: Partial<Styles> = {
  options: {
    arrowColor: 'transparent',
    backgroundColor: '#ffffff',
    overlayColor: 'rgba(0, 0, 0, 0.5)',
    primaryColor: '#3b82f6',
    textColor: '#1f2937',
    zIndex: 10000,
  },
  tooltip: {
    borderRadius: '0.5rem',
    padding: '1rem',
  },
  buttonNext: {
    backgroundColor: '#3b82f6',
    borderRadius: '0.375rem',
    color: '#ffffff',
    padding: '0.5rem 1rem',
    fontSize: '0.875rem',
    fontWeight: 500,
  },
  buttonBack: {
    color: '#6b7280',
    marginRight: '0.5rem',
    fontSize: '0.875rem',
  },
  buttonSkip: {
    color: '#ef4444',
    fontSize: '0.875rem',
  },
  buttonClose: {
    display: 'none',
  },
};

const darkTourStyles: Partial<Styles> = {
  options: {
    ...tourStyles.options,
    backgroundColor: '#1f2937',
    textColor: '#f3f4f6',
  },
  tooltip: tourStyles.tooltip,
  buttonNext: tourStyles.buttonNext,
  buttonBack: {
    ...tourStyles.buttonBack,
    color: '#9ca3af',
  },
  buttonSkip: tourStyles.buttonSkip,
  buttonClose: tourStyles.buttonClose,
};

// ================================================================================
// CONTEXT
// ================================================================================

const TourContext = createContext<TourContextValue | undefined>(undefined);

export const useTour = () => {
  const context = useContext(TourContext);
  if (!context) {
    throw new Error('useTour must be used within TourProvider');
  }
  return context;
};

// ================================================================================
// PROVIDER
// ================================================================================

interface TourProviderProps {
  children: React.ReactNode;
}

export const TourProvider: React.FC<TourProviderProps> = ({ children }) => {
  const { user } = useAuth();
  const [run, setRun] = useState(false);
  const [steps, setSteps] = useState<Step[]>([]);
  const [currentTourType, setCurrentTourType] = useState<TourType | null>(null);
  const [isDarkMode, setIsDarkMode] = useState(false);

  // Detectar dark mode
  useEffect(() => {
    const checkDarkMode = () => {
      setIsDarkMode(document.documentElement.classList.contains('dark'));
    };
    checkDarkMode();
    
    // Observer para mudanças de tema
    const observer = new MutationObserver(checkDarkMode);
    observer.observe(document.documentElement, {
      attributes: true,
      attributeFilter: ['class'],
    });

    return () => observer.disconnect();
  }, []);

  // Auto-iniciar tour no primeiro acesso
  useEffect(() => {
    if (!user) return;

    const userRole = typeof user.role === 'string' ? user.role : (user.role as any);
    if (!userRole) return;

    // Mapear role para tour type
    let tourType: TourType | null = null;
    if (['treinador', 'coordenador', 'dirigente'].includes(userRole)) {
      tourType = 'coach';
    } else if (userRole === 'atleta') {
      tourType = 'athlete';
    }

    if (!tourType) return;

    // Verificar se tour já foi completado
    const storageKey = `tour_completed_${tourType}`;
    const completed = localStorage.getItem(storageKey);

    if (!completed) {
      // Aguardar 1 segundo para garantir que a UI foi renderizada
      const timer = setTimeout(() => {
        startTour(tourType!);
      }, 1000);

      return () => clearTimeout(timer);
    }
  }, [user]);

  const startTour = useCallback((type: TourType) => {
    const tourSteps = type === 'coach' ? COACH_TOUR_STEPS : ATHLETE_TOUR_STEPS;
    setSteps(tourSteps);
    setCurrentTourType(type);
    setRun(true);
  }, []);

  const skipTour = useCallback(() => {
    setRun(false);
    setSteps([]);
    setCurrentTourType(null);
  }, []);

  const resetTour = useCallback((type: TourType) => {
    const storageKey = `tour_completed_${type}`;
    localStorage.removeItem(storageKey);
    startTour(type);
  }, [startTour]);

  const handleJoyrideCallback = useCallback((data: CallBackProps) => {
    const { status, type } = data;

    if (status === STATUS.FINISHED || status === STATUS.SKIPPED) {
      setRun(false);
      
      // Salvar conclusão no localStorage
      if (currentTourType && status === STATUS.FINISHED) {
        const storageKey = `tour_completed_${currentTourType}`;
        localStorage.setItem(storageKey, 'true');
      }

      setSteps([]);
      setCurrentTourType(null);
    }
  }, [currentTourType]);

  const value: TourContextValue = {
    startTour,
    skipTour,
    isTourActive: run,
    currentTourType,
    resetTour,
  };

  return (
    <TourContext.Provider value={value}>
      {children}
      <Joyride
        steps={steps}
        run={run}
        continuous
        showProgress
        showSkipButton
        scrollToFirstStep
        disableScrolling={false}
        styles={isDarkMode ? darkTourStyles : tourStyles}
        callback={handleJoyrideCallback}
        locale={{
          back: 'Voltar',
          close: 'Fechar',
          last: 'Concluir',
          next: 'Próximo',
          skip: 'Pular Tour',
        }}
      />
    </TourContext.Provider>
  );
};

