'use client';

/**
 * useJourneyShortcuts - Hook para atalhos de jornada na sidebar
 * 
 * Gera atalhos dinâmicos baseados em:
 * - Rotas mais acessadas (telemetria)
 * - Contexto atual (ex: pós-jogo)
 * - Planejamento da semana
 * 
 * @version 1.0.0
 */

import { useMemo, useEffect, useState } from 'react';
import { useCallback } from 'react';
import { usePathname } from 'next/navigation';
import {
  CalendarClock,
  ClipboardCheck,
  TrendingUp,
  Dumbbell,
  Gamepad2,
  Star,
  type LucideIcon,
} from 'lucide-react';

// =============================================================================
// TIPOS
// =============================================================================

export interface JourneyShortcut {
  id: string;
  name: string;
  href: string;
  icon: LucideIcon;
  description?: string;
  condition?: 'always' | 'contextual' | 'frequent';
  priority: number;
}

interface UseJourneyShortcutsReturn {
  shortcuts: JourneyShortcut[];
  contextualShortcut: JourneyShortcut | null;
  frequentRoutes: JourneyShortcut[];
  addFrequentRoute: (route: string) => void;
}

// =============================================================================
// CONSTANTES
// =============================================================================

const STORAGE_KEY = 'hbtrack-route-frequency';
const MAX_FREQUENT_ROUTES = 3;

// Atalhos fixos baseados em jornadas principais
const FIXED_SHORTCUTS: JourneyShortcut[] = [
  {
    id: 'weekly-planning',
    name: 'Planejamento da Semana',
    href: '/training/agenda',
    icon: CalendarClock,
    description: 'Ver e planejar treinos da semana',
    condition: 'always',
    priority: 1,
  },
  {
    id: 'next-game',
    name: 'Próximo Jogo',
    href: '/games',
    icon: Gamepad2,
    description: 'Preparação para o próximo jogo',
    condition: 'always',
    priority: 2,
  },
];

// Atalhos contextuais (aparecem em situações específicas)
const CONTEXTUAL_SHORTCUTS: Record<string, JourneyShortcut> = {
  'post-game': {
    id: 'post-game-analysis',
    name: 'Avaliação Pós-Jogo',
    href: '/games/relatorio',
    icon: ClipboardCheck,
    description: 'Registrar análise do jogo',
    condition: 'contextual',
    priority: 0,
  },
  'pre-training': {
    id: 'training-prep',
    name: 'Preparar Treino',
    href: '/training/planejamento',
    icon: Dumbbell,
    description: 'Definir atividades do treino',
    condition: 'contextual',
    priority: 0,
  },
  'review-stats': {
    id: 'review-stats',
    name: 'Revisar Estatísticas',
    href: '/statistics/teams',
    icon: TrendingUp,
    description: 'Analisar desempenho da equipe',
    condition: 'contextual',
    priority: 0,
  },
};

// Mapeamento de rotas para atalhos contextuais
const ROUTE_TO_CONTEXTUAL: Record<string, string> = {
  '/games': 'post-game',
  '/games/': 'post-game',
  '/training': 'pre-training',
  '/training/agenda': 'pre-training',
  '/dashboard': 'review-stats',
};

// =============================================================================
// HOOK
// =============================================================================

export function useJourneyShortcuts(): UseJourneyShortcutsReturn {
  const pathname = usePathname();
  const [routeFrequency, setRouteFrequency] = useState<Record<string, number>>({});

  // Carregar frequência do localStorage
  useEffect(() => {
    if (typeof window !== 'undefined') {
      try {
        const stored = localStorage.getItem(STORAGE_KEY);
        if (stored) {
          setRouteFrequency(JSON.parse(stored));
        }
      } catch (e) {
        // Ignorar erro de parse
      }
    }
  }, []);

  // Determinar atalho contextual baseado na rota atual
  const contextualShortcut = useMemo(() => {
    // Verificar se a rota atual tem um atalho contextual
    for (const [route, shortcutKey] of Object.entries(ROUTE_TO_CONTEXTUAL)) {
      if (pathname.startsWith(route)) {
        const shortcut = CONTEXTUAL_SHORTCUTS[shortcutKey];
        // Não mostrar o atalho se já estamos na rota dele
        if (shortcut && !pathname.startsWith(shortcut.href)) {
          return shortcut;
        }
      }
    }
    return null;
  }, [pathname]);

  // Calcular rotas frequentes
  const frequentRoutes = useMemo(() => {
    const entries = Object.entries(routeFrequency);
    if (entries.length === 0) return [];

    // Ordenar por frequência
    const sorted = entries
      .sort(([, a], [, b]) => b - a)
      .slice(0, MAX_FREQUENT_ROUTES);

    // Converter para atalhos
    return sorted.map(([route, count], index) => ({
      id: `frequent-${index}`,
      name: getRouteLabel(route),
      href: route,
      icon: Star,
      description: `Acessado ${count}x`,
      condition: 'frequent' as const,
      priority: 10 + index,
    }));
  }, [routeFrequency]);

  // Adicionar rota à frequência
  const addFrequentRoute = useCallback((route: string) => {
    // Ignorar rotas de autenticação
    if (route.includes('/signin') || route.includes('/signup')) return;
    
    // Normalizar rota para lowercase (evita /OVERVIEW vs /overview)
    const normalizedRoute = route.toLowerCase();
    
    setRouteFrequency(prev => {
      const updated = {
        ...prev,
        [normalizedRoute]: (prev[normalizedRoute] || 0) + 1,
      };
      
      // Salvar no localStorage
      if (typeof window !== 'undefined') {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(updated));
      }
      
      return updated;
    });
  }, []);

  // Rastrear navegação automaticamente
  useEffect(() => {
    if (pathname) {
      addFrequentRoute(pathname);
    }
  }, [pathname, addFrequentRoute]);

  // Combinar todos os atalhos
  const shortcuts = useMemo(() => {
    const all: JourneyShortcut[] = [...FIXED_SHORTCUTS];
    
    // Adicionar contextual se existir
    if (contextualShortcut) {
      all.unshift(contextualShortcut);
    }
    
    // Ordenar por prioridade
    return all.sort((a, b) => a.priority - b.priority);
  }, [contextualShortcut]);

  return {
    shortcuts,
    contextualShortcut,
    frequentRoutes,
    addFrequentRoute,
  };
}

// =============================================================================
// HELPERS
// =============================================================================

function getRouteLabel(route: string): string {
  const labels: Record<string, string> = {
    '/dashboard': 'Dashboard',
    '/games': 'Jogos',
    '/training': 'Treinos',
    '/training/agenda': 'Agenda de Treinos',
    '/training/planejamento': 'Planejamento',
    '/teams': 'Equipes',
    '/admin/athletes': 'Atletas',
    '/statistics': 'Estatísticas',
    '/calendar': 'Calendário',
  };
  
  return labels[route] || route.split('/').pop()?.replace(/-/g, ' ') || route;
}

export default useJourneyShortcuts;

'use client';

/**
 * useNavigationTelemetry - Hook para telemetria de navegação
 * 
 * Rastreia:
 * - Páginas visitadas
 * - Tempo de permanência
 * - Frequência de acesso
 * - Padrões de navegação
 * 
 * Pode ser integrado com:
 * - PostHog
 * - Segment
 * - Plausible
 * - Custom analytics
 * 
 * @version 1.0.0
 */

import { useEffect, useRef, useCallback } from 'react';
import { usePathname } from 'next/navigation';

interface NavigationEvent {
  pathname: string;
  timestamp: number;
  duration?: number; // Tempo na página anterior (ms)
  referrer?: string; // Página anterior
  sessionId: string;
}

interface TelemetryConfig {
  enabled: boolean;
  endpoint?: string; // URL para enviar dados
  batchSize?: number; // Quantos eventos acumular antes de enviar
  flushInterval?: number; // Intervalo para flush automático (ms)
  debug?: boolean; // Log no console
}

// Configuração padrão
const defaultConfig: TelemetryConfig = {
  enabled: process.env.NODE_ENV === 'production',
  batchSize: 10,
  flushInterval: 30000, // 30 segundos
  debug: process.env.NODE_ENV === 'development',
};

// Gerar ID de sessão único
function generateSessionId(): string {
  return `session_${Date.now()}_${Math.random().toString(36).substring(2, 9)}`;
}

// Storage key para persistir eventos
const TELEMETRY_STORAGE_KEY = 'hbtrack-navigation-telemetry';
const SESSION_ID_KEY = 'hbtrack-session-id';

// Obter ou criar session ID
function getSessionId(): string {
  if (typeof window === 'undefined') return '';
  
  let sessionId = sessionStorage.getItem(SESSION_ID_KEY);
  if (!sessionId) {
    sessionId = generateSessionId();
    sessionStorage.setItem(SESSION_ID_KEY, sessionId);
  }
  return sessionId;
}

// Classe para gerenciar telemetria
class NavigationTelemetryManager {
  private events: NavigationEvent[] = [];
  private config: TelemetryConfig;
  private flushTimer: NodeJS.Timeout | null = null;
  private sessionId: string;

  constructor(config: TelemetryConfig = defaultConfig) {
    this.config = { ...defaultConfig, ...config };
    this.sessionId = getSessionId();
    this.loadFromStorage();
    this.startFlushTimer();
  }

  private loadFromStorage() {
    if (typeof window === 'undefined') return;
    
    try {
      const stored = localStorage.getItem(TELEMETRY_STORAGE_KEY);
      if (stored) {
        this.events = JSON.parse(stored);
      }
    } catch (e) {
      // Ignorar erro de parse
    }
  }

  private saveToStorage() {
    if (typeof window === 'undefined') return;
    
    try {
      localStorage.setItem(TELEMETRY_STORAGE_KEY, JSON.stringify(this.events));
    } catch (e) {
      // Ignorar erro de storage cheio
    }
  }

  private startFlushTimer() {
    if (this.flushTimer) clearInterval(this.flushTimer);
    
    if (this.config.flushInterval && this.config.enabled) {
      this.flushTimer = setInterval(() => {
        this.flush();
      }, this.config.flushInterval);
    }
  }

  track(event: Omit<NavigationEvent, 'sessionId'>) {
    if (!this.config.enabled && !this.config.debug) return;

    const fullEvent: NavigationEvent = {
      ...event,
      sessionId: this.sessionId,
    };

    this.events.push(fullEvent);
    this.saveToStorage();

    if (this.config.debug) {
      console.log('[Telemetry] Navigation:', fullEvent);
    }

    // Auto-flush se atingiu batch size
    if (this.config.batchSize && this.events.length >= this.config.batchSize) {
      this.flush();
    }
  }

  async flush() {
    if (this.events.length === 0) return;
    if (!this.config.enabled) {
      if (this.config.debug) {
        console.log('[Telemetry] Would flush events:', this.events);
      }
      return;
    }

    const eventsToSend = [...this.events];
    this.events = [];
    this.saveToStorage();

    if (this.config.endpoint) {
      try {
        await fetch(this.config.endpoint, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ events: eventsToSend }),
        });
        
        if (this.config.debug) {
          console.log('[Telemetry] Flushed events:', eventsToSend.length);
        }
      } catch (e) {
        // Re-adicionar eventos em caso de falha
        this.events = [...eventsToSend, ...this.events];
        this.saveToStorage();
        
        if (this.config.debug) {
          console.error('[Telemetry] Flush failed:', e);
        }
      }
    }
  }

  getAnalytics() {
    // Análise local dos eventos
    const pageVisits: Record<string, number> = {};
    const avgDuration: Record<string, number[]> = {};

    this.events.forEach(event => {
      pageVisits[event.pathname] = (pageVisits[event.pathname] || 0) + 1;
      
      if (event.duration) {
        if (!avgDuration[event.pathname]) {
          avgDuration[event.pathname] = [];
        }
        avgDuration[event.pathname].push(event.duration);
      }
    });

    const avgDurationByPage: Record<string, number> = {};
    Object.entries(avgDuration).forEach(([path, durations]) => {
      avgDurationByPage[path] = durations.reduce((a, b) => a + b, 0) / durations.length;
    });

    return {
      pageVisits,
      avgDurationByPage,
      totalEvents: this.events.length,
      sessionId: this.sessionId,
    };
  }

  destroy() {
    if (this.flushTimer) {
      clearInterval(this.flushTimer);
    }
  }
}

// Instância singleton
let telemetryManager: NavigationTelemetryManager | null = null;

function getTelemetryManager(config?: TelemetryConfig): NavigationTelemetryManager {
  if (!telemetryManager) {
    telemetryManager = new NavigationTelemetryManager(config);
  }
  return telemetryManager;
}

/**
 * Hook para rastrear navegação automaticamente
 */
export function useNavigationTelemetry(config?: Partial<TelemetryConfig>) {
  const pathname = usePathname();
  const lastPathRef = useRef<string | null>(null);
  const lastTimestampRef = useRef<number | null>(null);

  // Inicializar timestamp apenas na primeira utilização
  const getInitialTimestamp = useCallback(() => {
    if (lastTimestampRef.current === null) {
      lastTimestampRef.current = Date.now();
    }
    return lastTimestampRef.current;
  }, []);

  // Função para rastrear manualmente (ex: cliques em sidebar)
  const trackNavigation = useCallback((path: string, extra?: Record<string, unknown>) => {
    const manager = getTelemetryManager(config as TelemetryConfig);
    const now = getInitialTimestamp();
    const duration = lastPathRef.current && lastTimestampRef.current ? now - lastTimestampRef.current : undefined;
    
    manager.track({
      pathname: path,
      timestamp: now,
      duration,
      referrer: lastPathRef.current || undefined,
      ...extra,
    });

    lastPathRef.current = path;
    lastTimestampRef.current = now;
  }, [config]);

  // Rastrear automaticamente mudanças de rota
  useEffect(() => {
    if (pathname && pathname !== lastPathRef.current) {
      trackNavigation(pathname);
    }
  }, [pathname, trackNavigation]);

  // Flush ao sair da página
  useEffect(() => {
    const handleBeforeUnload = () => {
      const manager = getTelemetryManager();
      manager.flush();
    };

    window.addEventListener('beforeunload', handleBeforeUnload);
    return () => {
      window.removeEventListener('beforeunload', handleBeforeUnload);
    };
  }, []);

  // Retornar funções úteis
  return {
    trackNavigation,
    getAnalytics: () => getTelemetryManager().getAnalytics(),
    flush: () => getTelemetryManager().flush(),
  };
}

export default useNavigationTelemetry;

